export const STRATEGIC_V4_PROMPTS = [
  { id: "s4-001", category: "architecte-interieur", title: "Audit complet d'un projet de renovation", content: "Tu es un architecte d'interieur senior specialise en renovation residentielle haut de gamme avec 15 ans d'experience. Realise un audit complet du projet suivant : [decrire le projet - surface, etat actuel, objectifs, budget, contraintes]. Structure ton analyse en 5 axes : (1) analyse technique du bati existant et contraintes structurelles, (2) potentiel de valorisation par rapport au marche local, (3) priorisation des travaux selon le ratio impact/cout, (4) risques identifies et mesures preventives, (5) recommandation chiffree avec phasage sur 3 niveaux de budget. Sois precis, factuel, et conclus par une recommandation claire pour le client." },
  { id: "s4-002", category: "architecte-interieur", title: "Strategie de positionnement tarifaire", content: "Tu es un expert en strategie commerciale pour les architectes d'interieur independants. Analyse mon positionnement tarifaire actuel et construis une strategie d'optimisation. Mes tarifs actuels : [liste]. Mes concurrents directs : [liste avec tarifs si connus]. Ma zone geographique : [ville]. Mon profil client cible : [description]. Propose : (1) une analyse comparative de mon positionnement sur le marche, (2) une recommandation de grille tarifaire avec justification par la valeur, (3) une strategie de presentation des prix pour reduire la sensibilite au cout, (4) des arguments pour defendre mes tarifs face aux objections les plus frequentes, (5) une offre d'entree de gamme et une offre premium coherentes avec mon positionnement." },
  { id: "s4-003", category: "architecte-interieur", title: "Plan de contenu LinkedIn 90 jours", content: "Tu es un expert en strategie de contenu pour les professionnels creatifs sur LinkedIn. Concois un plan de contenu sur 90 jours pour un architecte d'interieur independant base a [ville], specialise en [specialite]. Objectif : generer 3 a 5 demandes de devis qualifiees par mois via LinkedIn. Le plan doit inclure : (1) analyse des piliers de contenu adaptes au metier (avant/apres, pedagogie, coulisses, temoignages, positionnement), (2) calendrier de publication semaine par semaine avec sujet, format et angle pour chaque post, (3) 5 accroches a fort taux d'engagement adaptees a la cible, (4) strategie d'engagement (commentaires, reseau, hashtags), (5) KPIs a suivre et frequence de revision." },
  { id: "s4-004", category: "architecte-interieur", title: "Analyse de rentabilite d'une mission", content: "Tu es un expert en gestion financiere pour les independants creatifs. Analyse la rentabilite de cette mission d'architecture d'interieur : honoraires factures [montant], duree estimee [X semaines], nombre de reunions prevues [N], deplacements [frequence], sous-traitants eventuels [liste et couts]. Calcule : (1) le taux journalier moyen reel vs mon TJM cible de [montant], (2) le seuil de rentabilite de la mission, (3) les postes de depassement les plus probables et leur impact, (4) les clauses contractuelles a prevoir pour me proteger, (5) une recommandation sur l'acceptation ou la renegociation de la mission avec arguments chiffres." },
  { id: "s4-005", category: "architecte-interieur", title: "Strategie de developpement client par recommandation", content: "Tu es un expert en developpement commercial par le bouche-a-oreille pour les professionnels du cadre de vie. Concois une strategie complete pour generer 80% de mon chiffre d'affaires via les recommandations. Actuellement mes sources d'acquisition sont : [liste]. Mes clients les plus satisfaits sont dans le segment [profil]. Construis : (1) une cartographie de mon reseau prescripteur potentiel (notaires, agents immobiliers, decorateurs, entrepreneurs), (2) un programme de recommandation formalise avec mecanisme d'activation, (3) les scripts de demande de recommandation selon le profil du client, (4) un systeme de suivi et de relance du reseau, (5) des indicateurs pour mesurer l'efficacite et ajuster la strategie trimestriellement." },
  { id: "s4-006", category: "architecte-interieur", title: "Diagnostic d'un client difficile", content: "Tu es un expert en gestion de la relation client pour les professionnels creatifs. Analyse cette situation client problematique : [decrire la situation en detail - type de client, nature du conflit, historique des echanges, enjeux financiers]. Fournis : (1) une analyse des causes profondes du conflit (attentes mal calibrees / communication insuffisante / probleme technique / budget depasse), (2) une evaluation des risques - financier, reputation, juridique, (3) une strategie de resolution en 3 phases avec scripts de communication precis, (4) les concessions acceptables vs les lignes rouges a ne pas franchir, (5) les lecons a integrer dans mon process client pour eviter ce type de situation a l'avenir." },
  { id: "s4-007", category: "architecte-interieur", title: "Offre de service packagee premium", content: "Tu es un expert en construction d'offres pour les architectes d'interieur haut de gamme. Concois 3 offres packagees distinctes qui maximisent la valeur percue et facilitent la decision d'achat. Mon positionnement : [description]. Mes clients cibles : [profil]. Mes prestations actuelles : [liste]. Pour chaque package definis : (1) le nom et le positionnement emotionnel, (2) le contenu detaille des livrables, (3) le tarif et la justification par la valeur, (4) le profil client ideal, (5) les arguments de vente differenciants. Ajoute une analyse de la mecanique de montee en gamme entre les 3 offres pour maximiser la valeur moyenne par client." },
  { id: "s4-008", category: "architecte-interieur", title: "Analyse concurrentielle du marche local", content: "Tu es un expert en analyse de marche pour les professions creatives independantes. Construis un cadre d'analyse concurrentielle complet pour un cabinet d'architecture d'interieur base a [ville]. Analyse : (1) segmentation du marche local - acteurs en presence, positionnements, gammes de prix, specialites, (2) identification des espaces de marche non ou mal adresses, (3) analyse des forces et faiblesses de mon positionnement actuel par rapport aux concurrents identifies [liste si connus], (4) strategie de differenciation recommandee avec arguments concrets, (5) opportunites a saisir dans les 12 prochains mois avec plan d'action priorise." },
  { id: "s4-009", category: "architecte-interieur", title: "Systeme de suivi et de relance des devis", content: "Tu es un expert en optimisation commerciale pour les independants du secteur creatif. Concois un systeme complet de suivi et de relance des devis pour un cabinet d'architecture d'interieur. Donnees actuelles : taux de transformation des devis [X]%, delai moyen de decision [Y] jours, valeur moyenne d'un devis [montant]. Construis : (1) un processus de qualification des prospects avant envoi de devis pour reduire le volume sans valeur, (2) une sequence de relance en 4 etapes avec les messages exacts a envoyer (J+3, J+7, J+14, J+30), (3) les techniques de reactivation des devis dormants de plus de 30 jours, (4) un script de closing telephonique pour convertir les indecis, (5) un tableau de bord simple a mettre en place pour piloter le pipeline commercial." },
  { id: "s4-010", category: "architecte-interieur", title: "Plan de developpement sur 2 ans", content: "Tu es un expert en strategie de developpement pour les independants creatifs. Construis un plan de developpement sur 24 mois pour un cabinet d'architecture d'interieur solo base a [ville] avec un CA actuel de [montant] et un objectif de [montant cible]. Analyse : (1) les leviers de croissance prioritaires selon mon profil (nouveaux segments, geographie, services complementaires, sous-traitance, formation), (2) le chemin critique mois par mois pour atteindre l'objectif, (3) les investissements necessaires (temps, argent, competences) et leur ROI estime, (4) les risques principaux et les plans de contingence, (5) les indicateurs cles a suivre chaque mois pour piloter l'execution et ajuster le plan." },
  { id: "s4-011", category: "plombier-independant", title: "Strategie de developpement local", content: "Tu es un expert en developpement commercial pour les artisans independants. Concois une strategie complete de developpement sur un secteur geographique de [X] km autour de [ville] pour un plombier independant. Analyse : (1) cartographie de la concurrence locale - nombre d'acteurs, positionnements, forces et faiblesses identifiables, (2) segments de clientele les plus rentables a adresser en priorite (particuliers aises, coproprietes, agences immobilieres, syndics, gestionnaires de biens), (3) strategie de visibilite locale - Google My Business, annuaires, partenariats prescripteurs, (4) systeme de fidelisation et de generation de recommandations, (5) objectifs chiffres et indicateurs de suivi sur 12 mois." },
  { id: "s4-012", category: "plombier-independant", title: "Optimisation de la rentabilite des interventions", content: "Tu es un expert en gestion financiere pour les artisans du BTP. Analyse la rentabilite de mon activite de plomberie et propose des optimisations. Donnees actuelles : CA mensuel moyen [montant], nombre d'interventions par mois [N], tarif horaire moyen [montant], temps de deplacement moyen [X%] du temps travaille, taux de rappel pour SAV [Y%]. Calcule et optimise : (1) le TJM optimal selon mes charges et objectifs de revenus nets, (2) le rayon d'intervention maximal rentable, (3) la structure tarifaire optimale (forfait deplacement, tarif horaire, majorations), (4) les types d'interventions les plus et moins rentables a adresser ou eviter, (5) un plan d'action concret pour augmenter le revenu net de [X]% en 6 mois." },
  { id: "s4-013", category: "plombier-independant", title: "Systeme de gestion des urgences et astreintes", content: "Tu es un expert en organisation pour les artisans independants. Concois un systeme complet de gestion des urgences pour un plombier souhaitant proposer un service d'astreinte rentable. Inclus : (1) analyse de la demande locale et du positionnement tarifaire des astreintes dans le secteur, (2) structure tarifaire de l'astreinte - forfait de deplacement nuit/weekend, majorations legales, seuil de rentabilite, (3) processus de qualification des urgences pour filtrer les vraies urgences des demandes non urgentes, (4) organisation personnelle et familiale pour tenir le service dans la duree, (5) communication et marketing du service d'astreinte pour en faire un avantage concurrentiel differenciant." },
  { id: "s4-014", category: "plombier-independant", title: "Plan de transition vers le haut de gamme", content: "Tu es un expert en repositionnement commercial pour les artisans. Concois un plan de transition pour un plombier qui souhaite migrer d'une clientele populaire vers une clientele haut de gamme (residences secondaires, appartements de luxe, clientele exigeante). Analyse : (1) les competences techniques et certifications a acquerir (PAC, plancher chauffant, domotique eau), (2) les investissements en outillage, vehicule et presentation necessaires, (3) la strategie de communication et de portfolio a construire, (4) les canaux d'acquisition specifiques a cette clientele (architectes, decorateurs, agences premium), (5) le plan de transition sur 18 mois avec etapes jalons et indicateurs de reussite." },
  { id: "s4-015", category: "plombier-independant", title: "Audit et optimisation de la presence digitale", content: "Tu es un expert en marketing digital pour les artisans locaux. Realise un audit complet et un plan d'optimisation de la presence digitale d'un plombier independant base a [ville]. Analyse et recommande sur : (1) Google My Business - optimisation complete de la fiche, strategie d'avis clients, posts reguliers, (2) site web - structure, mots-cles locaux prioritaires, pages de service a creer, optimisation technique basique, (3) plateformes d'annuaires - lesquelles prioriser, comment optimiser les fiches, (4) strategie d'acquisition d'avis clients - processus automatise, scripts de demande, gestion des avis negatifs, (5) budget temps mensuel realiste pour maintenir cette presence et ROI attendu en nombre de contacts generes." },
  { id: "s4-016", category: "plombier-independant", title: "Developpement d'une offre de contrats d'entretien", content: "Tu es un expert en business model pour les artisans independants. Concois une offre de contrats d'entretien annuels pour un plombier independant visant a creer un revenu recurrent. Construis : (1) analyse du marche et identification des segments les plus receptifs (proprietaires de maisons individuelles, gestionnaires de coproprietes, proprietaires bailleurs), (2) contenu detaille de 3 formules d'entretien a des niveaux de prix differents, (3) tarification optimale par rapport a la concurrence et au cout de revient, (4) argumentaire commercial et objections a traiter, (5) systeme de gestion operationnelle des contrats (planning, rappels, facturation) et projection de CA recurrent a 2 ans." },
  { id: "s4-017", category: "plombier-independant", title: "Gestion et developpement des partenariats prescripteurs", content: "Tu es un expert en developpement de reseau pour les artisans du BTP. Concois une strategie complete de developpement des partenariats prescripteurs pour un plombier independant. Identifie et priorise : (1) les 5 types de prescripteurs les plus generateurs de volume (agents immobiliers, syndics, maitres d'oeuvre, constructeurs, architectes), (2) une approche de prise de contact et de presentation adaptee a chaque type de prescripteur, (3) un systeme de suivi et d'entretien de la relation prescripteur dans le temps, (4) les conditions d'un partenariat gagnant-gagnant - delais, qualite, communication, facturation, (5) un tableau de bord de suivi du CA genere par prescripteur pour prioriser les efforts relationnels." },
  { id: "s4-018", category: "plombier-independant", title: "Plan de formation et montee en competences", content: "Tu es un expert en developpement des competences pour les artisans du BTP. Concois un plan de montee en competences sur 3 ans pour un plombier independant souhaitant se specialiser dans [specialite : pompes a chaleur / energies renouvelables / plomberie de luxe / renovation energetique]. Inclus : (1) cartographie des certifications et formations prioritaires avec couts, durees et organismes, (2) analyse du ROI de chaque certification en termes de nouveaux marches accessibles et de tarification possible, (3) plan de financement (OPCO, aides a la formation, subventions), (4) strategie de communication des nouvelles competences aupres des clients existants et prospects, (5) jalons de montee en puissance commerciale mois par mois." },
  { id: "s4-019", category: "plombier-independant", title: "Systeme de gestion administrative et comptable", content: "Tu es un expert en organisation pour les artisans independants. Concois un systeme de gestion administrative simple et efficace pour un plombier independant. Couvre : (1) processus de devis - outils recommandes, structure d'un devis professionnel, delais et suivis, (2) facturation - automatisation, conditions de paiement, gestion des impayes avec procedure de relance en 3 etapes, (3) gestion des stocks de pieces courantes - methode d'inventaire simple, seuils de reapprovisionnement, (4) suivi de la rentabilite mensuelle - tableau de bord en 5 indicateurs cles accessibles en 30 minutes par mois, (5) obligations legales et fiscales cles a ne pas manquer - charges, TVA, assurances, decennale." },
  { id: "s4-020", category: "plombier-independant", title: "Strategie de communication de crise", content: "Tu es un expert en communication de crise pour les artisans independants. Concois un plan de communication de crise pour un plombier independant faisant face a [situation : defaut majeur sur un chantier / litige client amplifie sur les reseaux / avis negatifs en cascade / accident sur chantier]. Analyse : (1) evaluation de l'impact reputationnel et financier potentiel, (2) strategie de reponse immediate - qui contacter, que dire, comment le dire, (3) plan de communication vers les clients actifs et le reseau prescripteur pour limiter la contagion, (4) actions correctives concretes a mettre en oeuvre et a communiquer, (5) plan de reconstruction de la reputation sur 6 mois avec indicateurs de suivi." },
  { id: "s4-021", category: "entrepreneur-independant", title: "Strategie de developpement commercial 12 mois", content: "Tu es un expert en developpement commercial pour les agences creatives independantes. Concois un plan de developpement commercial sur 12 mois pour Cinemark Azur, agence de placement de produits regionaux dans les productions cinematographiques independantes en region PACA. Contexte : [etat actuel - CA, nombre de clients, productions partenaires]. Construis : (1) analyse des segments de marques a adresser en priorite selon leur appetence au placement produit et leurs budgets communication, (2) sequence de prospection mensuelle avec objectifs quantifies et methodes, (3) strategie de montee en gamme des partenariats (du placement simple vers le partenariat de production), (4) indicateurs de pilotage et tableau de bord mensuel, (5) scenarios de croissance pessimiste/realiste/optimiste avec leviers d'action pour chaque scenario." },
  { id: "s4-022", category: "entrepreneur-independant", title: "Analyse et valorisation d'un placement produit", content: "Tu es un expert en mesure de valeur dans le secteur de la communication et du cinema. Concois une methodologie complete pour valoriser et chiffrer l'impact d'un placement de produit dans une production cinematographique independante. Inclus : (1) indicateurs de valeur mesurables - duree a l'ecran, qualite d'exposition, contexte scenaristique, audience estimee, (2) methode de calcul d'un equivalent valeur publicitaire (EVA) pour justifier le tarif aupres des marques, (3) comparaison avec d'autres formats communication (spot TV, affichage, digital) pour positionner le placement produit dans l'ecosysteme media, (4) template de rapport de valorisation post-production a remettre aux marques partenaires, (5) strategie tarifaire optimale selon le type de production et le niveau d'exposition." },
  { id: "s4-023", category: "entrepreneur-independant", title: "Developpement d'un reseau de producteurs partenaires", content: "Tu es un expert en developpement de reseau pour les intermediaires du secteur creatif. Concois une strategie complete pour developper et consolider un reseau de producteurs de films independants en PACA partenaires de Cinemark Azur. Analyse : (1) cartographie des producteurs independants actifs en PACA et identification des plus receptifs au modele de placement produit, (2) valeur apportee a chaque producteur - comment presenter Cinemark Azur comme un apport de financement partiel et non comme une contrainte creative, (3) structure d'un accord de partenariat type - commission, modalites d'integration, liberte creative preservee, (4) systeme de fidelisation des producteurs partenaires dans le temps, (5) strategie d'extension geographique vers Monaco, Corse et arc mediterraneen." },
  { id: "s4-024", category: "entrepreneur-independant", title: "Strategie digitale et contenu de marque", content: "Tu es un expert en strategie digitale pour les agences creatives independantes. Concois une strategie digitale complete pour Cinemark Azur visant a generer des demandes entrantes de marques PACA. Construis : (1) positionnement editorial - quel contenu produit une agence de placement produit pour attirer des marques (etudes de cas, coulisses, pedagogie sur le format), (2) strategie LinkedIn pour cibler les directeurs marketing de marques regionales - frequence, formats, angles, (3) strategie Instagram pour valoriser le cinema independant et l'ancrage regional - cible secondaire mais prescriptrice, (4) content plan 6 mois semaine par semaine avec sujets, formats et objectifs par post, (5) systeme de mesure et d'optimisation mensuel." },
  { id: "s4-025", category: "entrepreneur-independant", title: "Modele de contrat type marque-producteur", content: "Tu es un expert juridique specialise dans les contrats creatifs et de communication. Redige un cadre contractuel complet pour les accords de placement de produit geres par Cinemark Azur entre une marque PACA et un producteur independant. Inclus : (1) definition precise des obligations de chaque partie - marque, producteur, Cinemark Azur, (2) modalites techniques du placement - duree minimale d'exposition, qualite d'image, contexte scenaristique accepte ou refuse, (3) conditions financieres - acompte, solde, conditions de versement, penalites si non-respect, (4) droits d'utilisation des rushes par la marque pour ses propres communications, (5) clause de sortie et conditions de rupture. Format : clauses types redigees, utilisables comme base de travail pour un avocat." },
  { id: "s4-026", category: "entrepreneur-independant", title: "Analyse SWOT et positionnement strategique", content: "Tu es un expert en strategie pour les entreprises creatives independantes. Realise une analyse SWOT complete de Cinemark Azur et construis un positionnement strategique sur 3 ans. Contexte : [etat actuel de l'agence]. Analyse : (1) Forces - actifs uniques, competences differenciantes, reseau existant, (2) Faiblesses - ressources limitees, dependances, manques a combler, (3) Opportunites - tendances de marche, evolutions reglementaires, segments emergents, (4) Menaces - concurrence, fragilite du marche du cinema independant, cycles economiques. Conclus par : une recommandation de positionnement strategique differenciant, 3 axes de developpement prioritaires sur 3 ans, et les 5 actions a enclencher dans les 90 prochains jours." },
  { id: "s4-027", category: "entrepreneur-independant", title: "Systeme de prospection automatisee", content: "Tu es un expert en automatisation commerciale pour les agences independantes. Concois un systeme de prospection semi-automatise pour Cinemark Azur ciblant les directeurs marketing de marques PACA avec un budget communication de [montant minimum]. Construis : (1) criteres de qualification d'une marque cible - secteur, taille, budget estime, sensibilite au cinema regional, (2) sources de donnees pour construire le fichier prospect - methodes de scraping ethique, bases de donnees, reseaux professionnels, (3) sequence de prospection multicanal en 5 touchpoints (LinkedIn + email + telephone) avec messages exacts pour chaque etape, (4) workflow d'automatisation realisable avec les outils disponibles (n8n, Make, Sales Navigator), (5) indicateurs de performance et seuils de declenchement pour les relances manuelles." },
  { id: "s4-028", category: "entrepreneur-independant", title: "Strategie de pricing et montee en gamme", content: "Tu es un expert en strategie tarifaire pour les agences de communication creatives. Concois une strategie de pricing complete pour Cinemark Azur couvrant l'ensemble des niveaux de placement produit. Analyse : (1) structure tarifaire en 4 niveaux selon l'exposition - mention, apparition, scene dediee, partenariat de production - avec justification de chaque palier de prix, (2) variables qui font varier le tarif - duree de production, audience estimee, notoriete du realisateur, (3) strategie de bundling pour augmenter la valeur moyenne par contrat - combiner placement + droits d'utilisation + evenement de lancement, (4) politique de remise et conditions a respecter pour proteger la valeur percue, (5) projection de CA selon differentes configurations de portefeuille clients." },
  { id: "s4-029", category: "entrepreneur-independant", title: "Plan de communication pour le lancement", content: "Tu es un expert en strategie de lancement pour les agences creatives. Concois un plan de communication complet pour le lancement officiel de Cinemark Azur sur le marche PACA. Construis : (1) strategie de relations presse regionale - medias a cibler, angle du communique, timing, (2) evenement de lancement - format, invites strategiques, objectifs mesurables, (3) campagne de notoriete LinkedIn sur 30 jours post-lancement avec sequence de posts et objectifs, (4) activation du reseau existant - comment mobiliser les contacts actuels pour amplifier le lancement organiquement, (5) plan de suivi et de mesure de l'impact du lancement - indicateurs, delais d'evaluation, criteres de succes." },
  { id: "s4-030", category: "entrepreneur-independant", title: "Developpement de l'offre vers la production", content: "Tu es un expert en developpement strategique pour les acteurs de l'industrie creative. Concois une strategie d'evolution de Cinemark Azur depuis un role d'intermediaire vers un role de producteur associe ou co-producteur. Analyse : (1) conditions prealables a remplir - reseau, credibilite, ressources financieres, competences, (2) modele economique de la co-production et partage des risques et revenus avec les producteurs partenaires, (3) types de projets les plus adaptes pour une premiere co-production (court-metrage, documentaire regional, serie web), (4) financement disponible - CNC, Region PACA, aides europeennes, crowdfunding, marques partenaires, (5) plan de transition sur 3 ans avec etapes jalons et indicateurs de faisabilite." },
  { id: "s4-031", category: "jardinier-independant", title: "Strategie de developpement d'un portefeuille clients recurrents", content: "Tu es un expert en developpement commercial pour les artisans paysagistes independants. Concois une strategie complete pour developper un portefeuille de [X] clients en contrat d'entretien annuel generant un revenu mensuel recurrent de [montant]. Analyse : (1) segmentation des clients a valeur maximale - profil, localisation, taille du jardin, budget, (2) offre de contrat annuel irresistible - contenu des prestations, tarification, flexibilite, avantages exclusifs, (3) strategie d'acquisition de ces clients - canaux, approche, argumentaire, (4) systeme de fidelisation et d'anti-churn - suivi proactif, communication saisonniere, valeur ajoutee reguliere, (5) projection financiere mensuelle sur 24 mois avec courbe de montee en charge." },
  { id: "s4-032", category: "jardinier-independant", title: "Audit et optimisation de la tournee hebdomadaire", content: "Tu es un expert en optimisation operationnelle pour les artisans independants. Analyse ma tournee hebdomadaire actuelle et propose des optimisations pour maximiser le CA journalier. Donnees : [nombre de clients, zones geographiques, durees d'intervention, tarifs]. Construis : (1) analyse des pertes de temps non facturables actuelles (deplacements, chargement/dechargement, administratif), (2) plan de regroupement geographique optimal des interventions par jour de semaine, (3) calcul du CA horaire reel actuel vs potentiel optimise, (4) recommandations pour augmenter la densite client par zone (prospection ciblee dans les secteurs deja couverts), (5) seuil de distance maximale acceptable par intervention selon le tarif pratique." },
  { id: "s4-033", category: "jardinier-independant", title: "Developpement d'une offre de creation de jardins", content: "Tu es un expert en diversification pour les paysagistes independants. Concois une strategie pour developper une activite de creation de jardins en complement de l'entretien. Analyse : (1) competences techniques et certifications a acquerir si manquantes, (2) outillage et equipement supplementaires necessaires avec plan de financement, (3) positionnement et tarification de l'offre creation - comment se demarquer, sur quel segment se positionner, (4) canaux d'acquisition specifiques a la creation (architectes, promoteurs, notaires, Instagram), (5) gestion du chantier creation en parallele de l'activite entretien - planning, sous-traitance eventuelle, gestion du risque financier." },
  { id: "s4-034", category: "jardinier-independant", title: "Strategie de visibilite locale et reputation", content: "Tu es un expert en marketing local pour les artisans du cadre de vie. Concois une strategie complete de visibilite pour un jardinier independant sur le secteur de [ville/region]. Construis : (1) optimisation complete de la presence Google - fiche GMB, photos avant/apres, gestion des avis, posts saisonniers, (2) strategie Facebook et Instagram - contenu adapte, frequence realiste, objectifs mesurables, (3) partenariats locaux a developper - jardineries, pepinieres, architectes paysagistes, agents immobiliers, (4) programme de recommandation structure pour activer le bouche-a-oreille, (5) plan de contenus saisonniers pour rester visible toute l'annee et eduquer les prospects sur la valeur du jardinier professionnel." },
  { id: "s4-035", category: "jardinier-independant", title: "Gestion de la saisonnalite et lissage des revenus", content: "Tu es un expert en gestion financiere pour les artisans dont l'activite est saisonniere. Concois une strategie de lissage des revenus sur 12 mois pour un jardinier independant dont l'activite chute de [X]% en hiver. Analyse : (1) identification des prestations hivernales a developper - taille arbres dormants, nettoyage de toitures et gouttieres, installation decorations, (2) activites complementaires rentables en basse saison - formation, conseil, plans de jardin, (3) structure de tresorerie recommandee - provisions, epargne de precaution, gestion des charges en basse saison, (4) strategie de contrats annuels avec paiement lisse pour lisser les encaissements, (5) projection mensuelle de CA sur 12 mois avant et apres optimisation." },
  { id: "s4-036", category: "jardinier-independant", title: "Positionnement environnemental et certifications", content: "Tu es un expert en differenciation par la durabilite pour les professionnels du cadre de vie. Concois une strategie de positionnement environnemental pour un jardinier independant souhaitant se demarquer par son approche ecologique. Analyse : (1) certifications et labels pertinents a acquerir - jardinage biologique, phytosanitaire, Qualipaysage - avec couts et benefices commerciaux, (2) pratiques differenciantes a integrer et a communiquer (zero phytosanitaire, compostage, recuperation d'eau, plantation mellifere), (3) segment de clientele le plus receptif a ce positionnement et comment l'adresser, (4) argumentaire commercial montrant le lien entre jardinage ecologique et economies pour le client, (5) strategie de communication du positionnement - contenus, canaux, certifications a afficher." },
  { id: "s4-037", category: "jardinier-independant", title: "Developpement d'une mini-equipe", content: "Tu es un expert en developpement RH pour les artisans independants en croissance. Concois un plan de developpement pour passer d'un jardinier solo a une equipe de 2 a 3 personnes. Analyse : (1) seuil de CA et de carnet de commandes justifiant le premier recrutement, (2) choix du statut - salarie, apprenti, sous-traitant independant - avec analyse comparative charges/risques/flexibilite, (3) processus de recrutement et criteres de selection adaptes au metier, (4) organisation du travail en equipe - planning, autonomie, controle qualite, (5) impact sur la rentabilite - projection du CA supplementaire genere vs cout du recrutement, delai de retour sur investissement." },
  { id: "s4-038", category: "jardinier-independant", title: "Strategie de montee en gamme tarifaire", content: "Tu es un expert en strategie commerciale pour les artisans independants. Concois un plan de montee en gamme tarifaire sur 18 mois pour un jardinier independant qui souhaite augmenter son TJM de [montant actuel] a [montant cible] sans perdre ses clients. Analyse : (1) diagnostic de la valeur reelle apportee vs la valeur percue par les clients actuels - ecart a combler, (2) ameliorations concretes a apporter (qualite, presentation, materiel, ponctualite, compte-rendu) pour justifier la hausse, (3) segmentation des clients actuels selon leur potentiel a accepter la hausse, (4) strategie de communication de la revalorisation - timing, message, processus, (5) plan de remplacement des clients perdus par des clients a plus haute valeur." },
  { id: "s4-039", category: "jardinier-independant", title: "Plan de communication saisonniere automatisee", content: "Tu es un expert en automatisation marketing pour les artisans independants. Concois un plan de communication saisonniere automatise sur 12 mois pour un jardinier independant. Construis pour chaque trimestre : (1) theme saisonnier et angle pedagogique adapte, (2) contenu des messages a envoyer par SMS, email et reseaux sociaux, (3) offre ou service saisonnier a mettre en avant, (4) declencheurs d'envoi automatique bases sur des dates ou des conditions climatiques, (5) outils recommandes pour l'automatisation avec configuration simple. Objectif global : rester en contact mensuel avec 100% des clients sans y consacrer plus de 2 heures par mois." },
  { id: "s4-040", category: "jardinier-independant", title: "Developpement de l'activite conseil", content: "Tu es un expert en developpement de nouvelles lignes de service pour les paysagistes. Concois une offre de conseil en amenagement paysager pour un jardinier independant souhaitant facturer son expertise au-dela des interventions physiques. Analyse : (1) format de l'offre conseil - diagnostic de jardin, plan d'amenagement, conseil a distance, formation proprietaires, (2) tarification de la prestation intellectuelle vs la prestation physique - comment justifier un tarif superieur, (3) clients les plus receptifs au conseil payant et comment les identifier dans le portefeuille existant, (4) supports a creer - rapport de diagnostic type, plan d'amenagement standardise, guide saisonnier personnalise, (5) positionnement marketing de l'offre conseil pour se differencier des jardiniers classiques." },
  { id: "s4-041", category: "artiste-sculpteur", title: "Strategie de developpement commercial galeries et institutions", content: "Tu es un expert en developpement commercial pour les artistes visuels contemporains. Concois une strategie complete de developpement aupres des galeries d'art et institutions culturelles pour EZEA, marque de sculptures en resine a incrustation street art. Analyse : (1) cartographie des galeries cibles par niveau - galeries locales PACA, galeries parisiennes, galeries internationales - avec criteres de selection et approche adaptee a chaque niveau, (2) dossier artistique ideal - structure, contenu, visuels, biographie, declaration d'intention, (3) strategie de prise de contact et de relance adaptee aux codes du monde de l'art, (4) conditions de partenariat a negocier avec les galeries - commission, exclusivite, pricing, logistique, (5) plan de progression sur 2 ans de la scene locale vers la scene nationale." },
  { id: "s4-042", category: "artiste-sculpteur", title: "Positionnement art et investissement", content: "Tu es un expert en marches de l'art et de l'investissement alternatif. Construis un argumentaire complet pour positionner les oeuvres EZEA comme actif d'investissement aupres des collectionneurs et investisseurs. Analyse : (1) elements qui fondent la valeur patrimoniale d'une oeuvre EZEA - unicite, processus, artiste, concept, edition limitee, (2) strategie de certificat d'authenticite et de tracabilite des oeuvres pour securiser l'investissement, (3) comparaison avec d'autres formes d'art contemporain en termes de potentiel de valorisation, (4) argumentaire adapte aux 3 profils d'acheteurs investisseurs - novice, amateur eclaire, collectionneur confirme, (5) strategie de pricing coherente avec un positionnement investissement - editions limitees, series numerotees, certificats, revente organisee." },
  { id: "s4-043", category: "artiste-sculpteur", title: "Developpement de l'offre commandes privees et corporate", content: "Tu es un expert en developpement d'offres sur-mesure pour les artistes a destination du marche corporate. Concois une strategie complete de developpement des commandes privees et corporate pour EZEA. Construis : (1) identification des clients corporate les plus receptifs - secteurs hotellerie, retail premium, sieges sociaux, promoteurs immobiliers, (2) offre d'art d'entreprise structuree - commande unique, serie de decoration, oeuvre evenementielle, (3) processus de creation d'une oeuvre sur commande - brief client, proposition, validation, production, livraison, (4) tarification des commandes corporate vs le marche galerie - justification de la prime sur-mesure, (5) canaux de prospection et d'approche adaptes au monde corporate - LinkedIn, architectes d'interieur, decorateurs, appels d'offres culturels." },
  { id: "s4-044", category: "artiste-sculpteur", title: "Strategie de visibilite digitale et reseaux sociaux", content: "Tu es un expert en strategie digitale pour les artistes visuels contemporains. Concois une strategie de visibilite digitale complete pour EZEA sur 12 mois. Analyse : (1) positionnement editorial - quelle narration construire autour de la marque EZEA pour attirer collectionneurs, galeries et marques, (2) strategie Instagram - frequence, formats (oeuvres, coulisses, processus, accrochage), techniques pour developper l'audience qualifiee, (3) strategie LinkedIn - cible corporate et collectionneurs professionnels, type de contenus, objectifs mesurables, (4) strategie YouTube ou Reels - coulisses de creation, presentation des oeuvres, concept artistique, (5) systeme de conversion de l'audience digitale en acheteurs - CTA, liste email, vente directe vs via galerie." },
  { id: "s4-045", category: "artiste-sculpteur", title: "Plan d'exposition et rayonnement geographique", content: "Tu es un expert en strategie d'exposition pour les artistes emergents. Concois un plan d'exposition progressif sur 3 ans pour EZEA permettant de construire une notoriete regionale puis nationale. Analyse : (1) cartographie des lieux d'exposition pertinents par niveau - espaces locaux, galeries regionales, foires d'art, (2) strategie de selection des expositions selon leur valeur carnet d'adresses, presse et ventes, (3) dossier de candidature type pour les appels a exposition - structure, contenu, visuels, references, (4) logistique et budget d'exposition - transport, accrochage, assurance, frais de participation, (5) systeme de capitalisation sur chaque exposition pour alimenter la notoriete - relations presse, documentation, reseaux sociaux, mailing liste." },
  { id: "s4-046", category: "artiste-sculpteur", title: "Strategie de pricing et editions limitees", content: "Tu es un expert en strategie tarifaire pour les artistes contemporains. Concois une strategie de pricing complete et une politique d'editions limitees pour EZEA. Analyse : (1) structure tarifaire coherente selon le format, les materiaux, la taille et l'unicite - grille de prix complete avec justification, (2) politique d'editions limitees - combien de pieces par serie, numerotation, certificats, (3) strategie de valorisation progressive des prix a mesure que la notoriete augmente - mecanisme de revision des tarifs, (4) coherence tarifaire entre vente directe, vente en galerie et commandes corporate, (5) politique de revente des oeuvres par les collectionneurs - suivi du marche secondaire, droit de suite, gestion de la cote." },
  { id: "s4-047", category: "artiste-sculpteur", title: "Developpement de collaborations avec des marques", content: "Tu es un expert en strategie de collaborations creatives entre artistes et marques. Concois une strategie de developpement de collaborations pour EZEA avec des marques premium ou lifestyle. Analyse : (1) identification des marques dont l'univers est coherent avec EZEA - secteurs mode, luxe, automobile, cosmetiques, art de vivre, (2) formats de collaboration possibles - edition limitee co-brandee, activation evenementielle, residence artistique, installation en boutique, (3) strategie d'approche des marques - who to contact, comment pitcher, quoi proposer, (4) conditions de la collaboration - remuneration, droits, duree, visibilite, (5) valorisation de la collaboration pour l'artiste - visibilite, audience, CA, legitimite." },
  { id: "s4-048", category: "artiste-sculpteur", title: "Systeme de suivi des collectionneurs", content: "Tu es un expert en gestion de la relation client pour les artistes et galeries. Concois un systeme de gestion et de fidelisation des collectionneurs pour EZEA. Construis : (1) base de donnees collectors - informations a collecter, outils de gestion simple, (2) programme de communication privilegiee - newsletter exclusive, avant-premieres, invitations privees, (3) strategie de montee en gamme des collectionneurs - comment les faire progresser vers des achats plus importants, (4) gestion des anniversaires d'acquisition - contact regulier, offres de revente organisee, oeuvres complementaires, (5) systeme de recommandation - comment transformer chaque collectionneur en prescripteur actif dans son reseau." },
  { id: "s4-049", category: "artiste-sculpteur", title: "Strategie de relations presse et medias", content: "Tu es un expert en relations presse pour les artistes contemporains. Concois une strategie complete de relations presse pour EZEA visant a construire une notoriete mediatique regionale puis nationale. Construis : (1) cartographie des medias cibles - presse regionale, presse art contemporain, presse lifestyle, medias digitaux - avec journalistes et chroniqueurs a identifier, (2) angles redactionnels adaptes a chaque type de media - comment rendre EZEA interessant pour chaque audience, (3) kit presse complet - communique type, biographie, visuels haute definition, contacts, (4) strategie de prise de contact et de relance journalistes - timing, canal, personnalisation, (5) plan de relations presse sur 12 mois avec jalons et objectifs de retombees mesurables." },
  { id: "s4-050", category: "artiste-sculpteur", title: "Developpement vers les foires d'art internationales", content: "Tu es un expert en developpement international pour les artistes contemporains. Concois une strategie d'acces aux foires d'art nationales et internationales pour EZEA sur un horizon de 3 ans. Analyse : (1) cartographie des foires accessibles par niveau - foires regionales, FIAC/Paris+ by Art Basel, foires internationales - avec criteres de selection et conditions d'entree, (2) strategie pour attirer une galerie partenaire qui presente les oeuvres EZEA en foire - comment devenir attractif pour une galerie, (3) preparation d'un corpus d'oeuvres coherent pour la foire - curation, accrochage, prix, (4) logistique et budget d'une participation en foire - couts, assurances, transport, frais de stand, (5) strategie de maximisation des contacts et ventes pendant et apres la foire." },
  { id: "s4-051", category: "coiffeur-independant", title: "Analyse complete de la clientele et segmentation", content: "Tu es un expert en analyse commerciale pour les salons de coiffure independants. Realise une analyse complete de mon portefeuille clients pour identifier les segments a fort potentiel. Donnees : [nombre de clients actifs, frequence de visite moyenne, panier moyen, repartition des prestations]. Construis : (1) segmentation client en 4 groupes selon valeur et frequence - champions, fideles, a potentiel, a risque - avec caracteristiques et effectifs estimes, (2) valeur a vie (LTV) de chaque segment et impact sur le CA, (3) strategie differenciee pour chaque segment - fideliser les champions, activer les a potentiel, recuperer les a risque, (4) identification des prestations a developper pour augmenter le panier moyen, (5) objectifs chiffres et plan d'action trimestriel." },
  { id: "s4-052", category: "coiffeur-independant", title: "Strategie de developpement des revenus recurrents", content: "Tu es un expert en business model pour les salons de coiffure independants. Concois une strategie complete pour developper les revenus recurrents de mon salon. Analyse et propose : (1) offre d'abonnement mensuel coiffure - structure, contenu, prix, avantages, gestion operationnelle, (2) programme de revente de produits capillaires - selection, marges, formation, argumentaire de vente, (3) offres de soins recurrents - keratine trimestrielle, coloration mensuelle - avec tarification et fidelisation integree, (4) partenariats locaux generateurs de trafic recurrent - entreprises pour coiffure evenementielle, ESN pour coiffure a domicile executives, (5) projection CA recurrent vs ponctuel sur 12 mois et seuil de rentabilite." },
  { id: "s4-053", category: "coiffeur-independant", title: "Plan de developpement digital et acquisition", content: "Tu es un expert en marketing digital pour les salons de coiffure independants. Concois une strategie d'acquisition digitale complete pour un salon base a [ville]. Objectif : [X] nouveaux clients par mois via le digital. Construis : (1) audit et optimisation Google My Business - fiche complete, photos professionnelles, gestion des avis, publications saisonnieres, referencement local, (2) strategie Instagram - piliers de contenu, frequence, formats Reels vs posts, partenariats locaux, (3) systeme de prise de rendez-vous en ligne - outil recommande, configuration, integration site, automatisations, (4) programme de parrainage digital - mecanique, recompenses, communication, (5) budget, temps a consacrer et ROI attendu par canal." },
  { id: "s4-054", category: "coiffeur-independant", title: "Strategie de montee en gamme de l'offre", content: "Tu es un expert en strategie de repositionnement pour les salons de coiffure. Concois un plan de montee en gamme pour un salon souhaitant augmenter son panier moyen de [montant actuel] a [montant cible]. Analyse : (1) audit de l'experience client actuelle - points de friction, axes d'amelioration, investissements necessaires, (2) construction d'une offre premium differenciante - prestations signature, produits exclusifs, experience sensorielle, (3) formation et posture commerciale de l'equipe - vente additionnelle, recommandation produits, upsell, (4) communication du repositionnement aupres des clients existants - risque de fuite et comment le minimiser, (5) recrutement de nouveaux clients plus haut de gamme - canaux, messages, partenariats." },
  { id: "s4-055", category: "coiffeur-independant", title: "Gestion et developpement de l'equipe", content: "Tu es un expert en management pour les dirigeants de salons de coiffure. Concois un systeme complet de gestion et de developpement d'une equipe de [X] collaborateurs. Inclus : (1) structure de remuneration motivante - fixe, variable, primes - coherente avec la rentabilite du salon, (2) systeme d'evaluation et de progression - criteres, frequence, entretiens, (3) plan de formation continue - techniques, vente, relation client - avec budget et organisation, (4) processus de recrutement et d'integration d'un nouveau collaborateur - sourcing, selection, periode d'essai, (5) indicateurs de performance par collaborateur et tableau de bord de management hebdomadaire." },
  { id: "s4-056", category: "coiffeur-independant", title: "Analyse de rentabilite et optimisation financiere", content: "Tu es un expert en gestion financiere pour les gerants de salons de coiffure. Realise un diagnostic complet de la rentabilite de mon salon et propose des optimisations. Donnees : [CA mensuel, loyer, masse salariale, achats produits, autres charges]. Analyse : (1) calcul du seuil de rentabilite reel et marge de securite, (2) decomposition de la marge par prestation pour identifier les plus et moins rentables, (3) taux d'occupation des fauteuils et optimisation du planning, (4) optimisation des achats produits - negociation fournisseurs, reduction du gaspillage, gestion des stocks, (5) 5 actions concretes pour ameliorer le resultat net de [X]% en 6 mois sans investissement majeur." },
  { id: "s4-057", category: "coiffeur-independant", title: "Strategie de fidelisation et programme VIP", content: "Tu es un expert en fidelisation client pour les commerces de service haut de gamme. Concois un programme de fidelisation complet pour un salon de coiffure independant. Construis : (1) segmentation des clients par valeur et definition des niveaux VIP - criteres d'entree, avantages exclusifs, (2) programme de points ou de benefices - mecanique simple, recompenses attractives, budget, (3) communication personnalisee par segment - messages, frequence, canal, (4) systeme de reactivation des clients inactifs - declencheurs, offres de retour, limite au-dela de laquelle un client est considere perdu, (5) mesure de l'impact du programme - taux de retention, frequence de visite, CA par client - avant/apres." },
  { id: "s4-058", category: "coiffeur-independant", title: "Developpement de l'activite evenementielle", content: "Tu es un expert en diversification pour les professionnels de la beaute. Concois une offre d'activite evenementielle rentable pour un coiffeur independant en complement du salon. Analyse : (1) types d'evenements a adresser selon leur rentabilite - mariages, soirees d'entreprise, shootings photo, fashion shows, coiffure a domicile executives, (2) structure tarifaire adaptee a chaque type d'evenement - deplacement, duree, equipe, (3) logistique necessaire - materiel portable, vehicule, equipe supplementaire, (4) canaux d'acquisition specifiques - agences evenementielles, wedding planners, photographes, DRH, (5) gestion de la complementarite salon/evenementiel - planning, disponibilite, rentabilite comparee." },
  { id: "s4-059", category: "coiffeur-independant", title: "Strategie de developpement par les reseaux professionnels", content: "Tu es un expert en developpement de reseau pour les professionnels de la beaute. Concois une strategie de developpement par les prescripteurs et reseaux professionnels pour un coiffeur independant. Identifie et priorise : (1) les 5 types de prescripteurs les plus generateurs - instituts de beaute, photographes, stylistes, agences de mannequins, boutiques de mode - avec approche specifique a chaque type, (2) strategie de partenariats croises locaux - offres combinees, recommandations mutuelles, operations communes, (3) participation aux reseaux professionnels locaux - BNI, chambres de commerce, associations de commercants - avec plan de ROI, (4) developpement d'une communaute de clientele - groupe prive, evenements clients, atelier coiffure, (5) systeme de suivi et de mesure du CA genere par prescripteur." },
  { id: "s4-060", category: "coiffeur-independant", title: "Plan de succession et valorisation du fonds", content: "Tu es un expert en transmission d'entreprises artisanales. Realise un diagnostic de la valorisation actuelle de mon salon de coiffure et concois un plan pour maximiser sa valeur en vue d'une transmission dans [X] ans. Analyse : (1) valorisation actuelle selon les methodes applicables - multiple de CA, multiple d'EBE, valeur du fonds clientele, (2) leviers de valorisation a activer - contrats clients, equipe fidelisee, notoriete, systemes documentes, (3) elements qui reduisent la valeur et comment les corriger - dependance a l'exploitant, manque de procedures, clientele fragile, (4) options de transmission - cession fonds, reprise salarie, location-gerance, franchise - avec analyse comparative, (5) plan d'action sur [X] ans pour atteindre la valeur cible de [montant]." },
  { id: "s4-061", category: "traiteur-evenementiel", title: "Strategie de developpement B2B et grands comptes", content: "Tu es un expert en developpement commercial B2B pour les prestataires evenementiels haut de gamme. Concois une strategie complete de developpement aupres des entreprises et grands comptes pour un traiteur evenementiel. Analyse : (1) segmentation des entreprises cibles selon leur potentiel - multinationales, ETI, grandes PME, secteurs d'activite prioritaires, (2) identification des decideurs a adresser - DRH, DAF, Office Manager, responsable evenements, (3) offre corporate structuree - cocktails, seminaires, team-buildings gastronomiques, repas d'affaires, (4) processus de prospection et de qualification adapte au cycle d'achat long des entreprises, (5) objectifs chiffres, indicateurs de suivi et projection CA B2B sur 24 mois." },
  { id: "s4-062", category: "traiteur-evenementiel", title: "Optimisation de la rentabilite par evenement", content: "Tu es un expert en gestion financiere pour les traiteurs evenementiels. Concois un systeme complet d'analyse et d'optimisation de la rentabilite par evenement. Construis : (1) modele de calcul du cout de revient reel d'un evenement - matieres premieres, personnel, deplacement, equipement, overhead, (2) structure tarifaire optimale avec marges cibles par type d'evenement et segment de clientele, (3) identification des evenements chronophages et peu rentables a eviter ou a requalifier, (4) leviers d'optimisation des couts - negociation fournisseurs, optimisation des equipes, gestion des invendus, (5) tableau de bord de rentabilite par evenement avec seuil d'alerte et processus de decision pour accepter ou refuser une demande." },
  { id: "s4-063", category: "traiteur-evenementiel", title: "Developpement de l'identite culinaire et differenciation", content: "Tu es un expert en positionnement pour les acteurs de la gastronomie evenementielle. Concois une strategie complete de differenciation culinaire pour un traiteur souhaitant se demarquer sur un marche concurrentiel. Analyse : (1) audit du positionnement culinaire actuel et analyse de la concurrence locale - qui fait quoi, quels espaces sont libres, (2) definition d'une identite culinaire forte et memorable - territoire, inspiration, signature technique, (3) developpement de 3 menus signatures qui incarnent cette identite - conception, couts, tarification, storytelling, (4) strategie de communication de l'identite culinaire - contenus visuels, argumentaire, relations presse gastronomique, (5) developpement de partenariats avec producteurs locaux pour ancrer l'identite territoriale et renforcer la differenciation." },
  { id: "s4-064", category: "traiteur-evenementiel", title: "Strategie de gestion des pics d'activite", content: "Tu es un expert en organisation pour les traiteurs evenementiels. Concois un systeme complet de gestion des periodes de forte activite pour un traiteur evenementiel. Analyse : (1) cartographie des pics d'activite annuels et hebdomadaires avec impact sur les ressources humaines, materielles et financieres, (2) strategie de capacite - personnel interimaire, equipement en location, sous-traitants fiables, (3) politique de pricing en periode de forte demande - yeld management tarifaire, conditions d'annulation renforcees, (4) processus de qualification et de priorisation des demandes en periode de saturation, (5) gestion de la qualite en periode de stress - check-lists, briefings renforces, controles qualite cles, systeme de feedback post-evenement." },
  { id: "s4-065", category: "traiteur-evenementiel", title: "Developpement d'une offre de formation et transmission", content: "Tu es un expert en diversification pour les chefs et traiteurs. Concois une offre de formation gastronomique pour les particuliers et professionnels en complement de l'activite traiteur. Analyse : (1) formats adaptes - cours particuliers, ateliers groupe, masterclass thematiques, team-building cuisine, (2) tarification et modele economique - couts, marges, volume necessaire, (3) logistique - lieu (atelier integre vs deplacement), materiel, fournitures, (4) canaux d'acquisition specifiques - sites de cours de cuisine, entreprises pour team-building, particuliers via Instagram, (5) synergies avec l'activite traiteur - comment la formation nourrit la notoriete et genere des clients evenementiels." },
  { id: "s4-066", category: "traiteur-evenementiel", title: "Plan de communication annuel", content: "Tu es un expert en strategie de communication pour les traiteurs evenementiels haut de gamme. Concois un plan de communication annuel complet. Construis mois par mois : (1) calendrier editorial adapte aux saisons evenementielles - mariages (mai-septembre), fetes d'entreprise (novembre-decembre), jardins (ete), (2) contenus a produire par canal - site web, Instagram, LinkedIn, email - avec templates et briefs creatifs, (3) strategie de relations presse gastronomique regionale et nationale - medias cibles, angles, calendrier d'envoi, (4) evenements professionnels a integrer - salons du mariage, foires gastronomiques, networking, (5) budget de communication recommande et repartition optimale entre les canaux." },
  { id: "s4-067", category: "traiteur-evenementiel", title: "Systeme de gestion des prestataires et sous-traitants", content: "Tu es un expert en gestion de la chaine d'approvisionnement pour les professionnels de l'evenementiel. Concois un systeme complet de gestion des prestataires et sous-traitants pour un traiteur evenementiel. Inclus : (1) cartographie des prestataires necessaires par type d'evenement - personnel de service, vaisselle, mobilier, decoration, sono, (2) criteres de selection et processus de qualification d'un nouveau prestataire, (3) contractualisation adaptee - conditions generales, penalites, assurances, (4) systeme de briefing et de controle qualite le jour J, (5) evaluation post-evenement et gestion du panel fournisseurs - fidelisation des meilleurs, remplacement des insuffisants." },
  { id: "s4-068", category: "traiteur-evenementiel", title: "Strategie de developpement geographique", content: "Tu es un expert en developpement territorial pour les prestataires evenementiels. Concois une strategie d'extension geographique pour un traiteur evenementiel souhaitant couvrir une zone plus large. Analyse : (1) analyse du rayon d'action actuel et identification des zones a fort potentiel non encore adressees, (2) impact logistique et financier de l'extension - couts de deplacement, equipement, personnel, seuil de rentabilite par zone, (3) strategie d'acquisition de clients dans les nouvelles zones - partenariats locaux, referencement geographique, salons regionaux, (4) adaptation de l'offre selon les specificites regionales - produits locaux, habitudes culturelles, concurrence locale, (5) phasage de l'extension geographique sur 24 mois avec objectifs et jalons." },
  { id: "s4-069", category: "traiteur-evenementiel", title: "Optimisation du processus devis-vente", content: "Tu es un expert en optimisation commerciale pour les prestataires haut de gamme. Concois un processus de vente optimise de la premiere demande a la signature du contrat pour un traiteur evenementiel. Construis : (1) questionnaire de qualification de la demande - 10 questions essentielles pour coter rapidement et filtrer les demandes non pertinentes, (2) structure d'un devis qui se vend seul - presentation, contenu, visuels, valeur exprimee, conditions, (3) strategie de presentation du devis - en personne vs email - et argumentation associee, (4) sequence de relance en 4 etapes pour les devis sans reponse avec messages exacts, (5) techniques de closing adaptees aux prestataires haut de gamme - creation d'urgence legitime, garanties, facilites de paiement." },
  { id: "s4-070", category: "traiteur-evenementiel", title: "Developpement d'une marque traiteur forte", content: "Tu es un expert en developpement de marque pour les acteurs de la gastronomie. Concois une strategie de developpement de marque complete pour un traiteur evenementiel souhaitant passer d'un positionnement artisan a une marque reconnue. Analyse : (1) diagnostic de marque actuel - notoriete, image percue, valeurs exprimees, coherence visuelle, (2) definition de l'identite de marque - territoire, valeurs, personnalite, promesse, (3) plateforme de marque complete - nom, logotype, charte graphique, ton editorial, (4) strategie de deploiement de la marque sur tous les touchpoints - tenues, vehicules, packaging, digital, papeterie, (5) budget de construction de marque sur 2 ans et ROI attendu en termes de notoriete, prix pratiques et positionnement marche." },
  { id: "s4-071", category: "chef-a-domicile", title: "Strategie de positionnement et d'offre premium", content: "Tu es un expert en strategie commerciale pour les chefs a domicile haut de gamme. Concois une strategie complete de positionnement premium pour un chef a domicile souhaitant se demarquer dans un marche de plus en plus concurrentiel. Analyse : (1) analyse concurrentielle du marche local - acteurs, positionnements, prix, points faibles exploitables, (2) definition d'un positionnement unique - territoire culinaire, signature, histoire personnelle differenciante, (3) construction d'une offre de valeur inegalee - ce qui justifie un tarif 30 a 50% superieur au marche, (4) strategie de communication du positionnement - visuels, mots, canaux, preuves sociales, (5) plan de montee progressive en tarification sur 18 mois avec jalons." },
  { id: "s4-072", category: "chef-a-domicile", title: "Developpement d'une clientele corporate haut de gamme", content: "Tu es un expert en developpement commercial B2B pour les prestataires culinaires d'exception. Concois une strategie complete de developpement d'une clientele corporate haut de gamme pour un chef a domicile. Analyse : (1) identification des clients corporate les plus rentables - dirigeants, cabinets d'avocats, family offices, agences de luxe, (2) offre corporate specifique - diners d'affaires, repas de direction, seminaires residentiels, (3) canaux d'acquisition - LinkedIn cible, partenariats conciergeries d'hotels de luxe, agences evenementielles, clubs d'affaires, (4) processus de qualification et de vente adapte aux decideurs corporate - delai de decision, budget, interlocuteurs, (5) suivi de la relation et developpement du CA dans le temps - fidelisation, montee en gamme, recommandations." },
  { id: "s4-073", category: "chef-a-domicile", title: "Strategie de developpement via Instagram", content: "Tu es un expert en strategie Instagram pour les chefs et professionnels de la gastronomie. Concois une strategie Instagram complete sur 6 mois pour un chef a domicile souhaitant generer [X] demandes qualifiees par mois. Construis : (1) positionnement editorial - quelle histoire raconter, quelle esthetique developper, quelle personnalite exprimer, (2) piliers de contenu - les 4 a 5 types de posts a alterner (plats, coulisses, clients, pedagogie, terroir), (3) plan de publication semaine par semaine sur 8 semaines avec sujet, format, legende type et hashtags, (4) strategie de developpement de la communaute - collaborations, partenariats, UGC, (5) systeme de conversion des abonnes en clients - CTA, messages directs, offre d'entree de gamme, processus de reservation." },
  { id: "s4-074", category: "chef-a-domicile", title: "Systeme de gestion et d'optimisation des couts matieres", content: "Tu es un expert en gestion des couts pour les chefs independants. Concois un systeme complet de gestion et d'optimisation des couts matieres pour un chef a domicile. Inclus : (1) methode de calcul du food cost cible selon le type de prestation et le positionnement tarifaire, (2) processus d'approvisionnement optimise - fournisseurs directs vs marche, negociation, planning d'achats, (3) strategie de menu engineering pour maximiser la marge brute tout en maintenant le niveau de qualite, (4) gestion du gaspillage - planification precise des quantites, reutilisation creative des surplus, (5) tableau de bord mensuel des couts matieres par prestation avec seuils d'alerte et actions correctives." },
  { id: "s4-075", category: "chef-a-domicile", title: "Developpement d'une offre de cours et ateliers", content: "Tu es un expert en developpement de nouvelles lignes de revenus pour les chefs independants. Concois une offre complete de cours et ateliers gastronomiques pour un chef a domicile. Analyse : (1) formats a developper selon leur rentabilite - cours particuliers, ateliers groupe, masterclasses, team-building, cours en ligne, (2) tarification optimale de chaque format - couts, marges, comparaison marche, (3) logistique - materiel necessaire, lieux (domicile client, espace loue, cuisine professionnelle partagee), (4) canaux d'acquisition specifiques aux cours - Airbnb Experiences, plateformes de cours, LinkedIn pour team-building, Instagram pour particuliers, (5) synergies entre l'activite cours et l'activite chef a domicile - comment l'un alimente l'autre." },
  { id: "s4-076", category: "chef-a-domicile", title: "Strategie de relations presse et notoriete", content: "Tu es un expert en relations presse pour les chefs et restaurateurs. Concois une strategie complete de relations presse pour un chef a domicile souhaitant developper sa notoriete mediatique. Construis : (1) angle editorial differenciant - quelle est l'histoire qui rend ce chef unique et mediatisable, (2) cartographie des medias cibles - presse gastronomique, lifestyle, regionale, digitale - avec journalistes specialises a identifier, (3) dossier de presse complet - biographie, philosophy culinaire, signature technique, visuels haute definition, (4) strategie de pitch adaptee a chaque type de media et d'opportunite editoriale, (5) calendrier de relations presse sur 12 mois avec jalons, objectifs de retombees et systeme de suivi." },
  { id: "s4-077", category: "chef-a-domicile", title: "Plan de developpement des partenariats prescripteurs", content: "Tu es un expert en developpement de reseau pour les prestataires culinaires d'exception. Concois une strategie de developpement des prescripteurs pour un chef a domicile. Identifie et active : (1) les prescripteurs a fort volume - concierges d'hotels de luxe, agences evenementielles, wedding planners, (2) les prescripteurs affinitaires - sommeliers, cavistes, traiteurs non concurrents, (3) processus d'approche et de pitch de chaque type de prescripteur, (4) conditions du partenariat - commission eventuelle, delais, processus de qualification, (5) systeme de suivi des prescriptions et de mesure du CA genere par source pour prioriser les efforts relationnels et les renforcer." },
  { id: "s4-078", category: "chef-a-domicile", title: "Optimisation tarifaire et construction de packages", content: "Tu es un expert en strategie tarifaire pour les prestataires de luxe. Concois une architecture tarifaire complete et une strategie de packages pour un chef a domicile. Construis : (1) grille de tarification coherente selon le nombre de convives, le type de menu, la duree et les eventuels supplements (transport, materiel, assistant), (2) 3 packages signature - entree de gamme, standard, prestige - avec contenu precis et tarif justifie par la valeur, (3) politique de supplements et d'options pour maximiser le panier moyen sans alourdir la decision d'achat, (4) strategie de tarification dynamique selon la saison et la demande - eviter les sous-tarifications en haute saison, (5) mecanisme d'acompte et conditions d'annulation protegeant le chiffre d'affaires." },
  { id: "s4-079", category: "chef-a-domicile", title: "Developpement d'une presence en ligne convertissante", content: "Tu es un expert en strategie web pour les prestataires culinaires independants. Concois une strategie de presence en ligne complete et convertissante pour un chef a domicile. Analyse : (1) architecture optimale d'un site web vitrine - pages essentielles, contenu de chaque page, call-to-action, systeme de reservation ou de prise de contact, (2) SEO local - mots-cles prioritaires, optimisation technique de base, strategie de contenu blog pour le referencement, (3) strategie Google My Business adaptee a l'activite chef a domicile, (4) collecte et affichage des avis et temoignages - processus, plateformes, affichage optimal, (5) tunnel de conversion de la visite a la demande de devis - optimisation de chaque etape avec outils de mesure." },
  { id: "s4-080", category: "chef-a-domicile", title: "Plan de gestion de la croissance", content: "Tu es un expert en developpement organisationnel pour les independants en croissance. Concois un plan de gestion de la croissance pour un chef a domicile qui approche de la saturation de sa capacite solo. Analyse : (1) diagnostic de la saturation - nombre maximum d'evenements par mois maintenable en qualite, seuils d'alerte, (2) options de croissance - assistant cuisinier, chef partenaire, brigade ponctuelle, (3) processus de delegation - quelles taches deleguer en premier, comment maintenir la qualite, (4) impact financier de chaque option de croissance - couts, revenus supplementaires, delai de retour sur investissement, (5) plan de recrutement et d'integration du premier collaborateur avec onboarding structure." },
  { id: "s4-081", category: "coach-sportif-independant", title: "Developpement d'une offre en ligne scalable", content: "Tu es un expert en developpement de business en ligne pour les coachs sportifs. Concois une strategie complete pour developper une offre de coaching en ligne generant des revenus passifs ou semi-passifs. Analyse : (1) audit des competences et du contenu existant mobilisable pour une offre digitale, (2) choix du format optimal selon les objectifs - programme video en acces, coaching asynchrone, application, challenge en groupe, (3) plateforme de diffusion recommandee et configuration technique simplifiee, (4) strategie de lancement - liste d'attente, beta-test, prix de lancement, (5) plan de croissance des revenus en ligne sur 12 mois - acquisition, retention, montee en gamme - avec projection CA et comparaison avec le coaching presentiel." },
  { id: "s4-082", category: "coach-sportif-independant", title: "Strategie de specialisation et de niche", content: "Tu es un expert en positionnement pour les coachs sportifs independants. Concois une strategie de specialisation permettant de doubler le tarif horaire en 18 mois. Analyse : (1) audit des competences techniques, certifications et resultats clients actuels pour identifier la niche de plus forte valeur, (2) analyse des niches les plus rentables sur le marche - leur taille, leur solvabilite, leur accessibilite, (3) plan de developpement des competences et certifications specifiques a la niche choisie, (4) repositionnement de la communication et de l'offre autour de la specialisation, (5) strategie d'acquisition des premiers clients dans la niche et plan de montee en credibilite - etudes de cas, certifications, partenariats medicaux." },
  { id: "s4-083", category: "coach-sportif-independant", title: "Developpement d'une activite corporate", content: "Tu es un expert en developpement commercial B2B pour les coachs sportifs. Concois une strategie complete de developpement d'une clientele corporate pour un coach sportif. Construis : (1) offre corporate structuree - bien-etre en entreprise, challenges sportifs, ateliers, coaching de dirigeants, (2) identification des DRH, responsables QVT et dirigeants a adresser en priorite selon la taille et le secteur des entreprises, (3) strategie de prospection B2B - LinkedIn Sales Navigator, salons RH, reseaux d'affaires, (4) argumentation ROI de l'investissement sportif en entreprise - absenteisme, productivite, marque employeur, (5) modeles de contrats et de facturation adaptes au B2B - forfait mensuel, pack de seances, abonnement annuel." },
  { id: "s4-084", category: "coach-sportif-independant", title: "Systeme de suivi et de retention clients", content: "Tu es un expert en gestion de la relation client pour les coachs sportifs independants. Concois un systeme complet de suivi et de retention des clients. Inclus : (1) processus de bilan mensuel client - methode de mesure des progres, format du compte-rendu, frequence des points, (2) systeme d'alerte precoce du desengagement - indicateurs de churn a surveiller, declencheurs d'action, (3) protocole de reengagement des clients qui montrent des signes de decrochage - message, offre, approach, (4) programme de progression et de renouvellement - comment presenter la suite du parcours de facon naturelle et non commerciale, (5) calcul de la LTV client et impact d'une amelioration de [X] points du taux de retention sur le CA annuel." },
  { id: "s4-085", category: "coach-sportif-independant", title: "Strategie de contenu et personal branding", content: "Tu es un expert en personal branding pour les coachs sportifs. Concois une strategie de contenu complete pour un coach sportif souhaitant devenir une reference dans sa niche. Analyse : (1) positionnement editorial unique - quel angle de vue differenciant adopter sur les sujets de la niche, (2) piliers de contenu adaptes a la cible - entrainement, nutrition, mental, success stories, science de la performance, (3) strategie multi-plateformes - Instagram (visuel), YouTube (pedagogie longue), LinkedIn (corporate), TikTok (discovery) - avec frequence et formats adaptes a chaque plateforme, (4) processus de creation de contenu efficace - batching, templates, outils, temps consacre, (5) systeme de conversion du contenu en clients - lead magnets, email list, offres d'entree de gamme." },
  { id: "s4-086", category: "coach-sportif-independant", title: "Optimisation du business model et revenus multiples", content: "Tu es un expert en business model pour les coachs sportifs independants. Analyse mon modele actuel et concois une architecture de revenus multiples reduisant la dependance au presentiel. Donnees : [CA actuel par source, temps passe, taux horaire moyen]. Construis : (1) cartographie des sources de revenus actuelles et analyse de leur scalabilite, (2) identification des 3 nouvelles sources de revenus les plus coherentes avec mon positionnement et ma capacite - coaching en ligne, formation de coachs, produits digitaux, partenariats marques, (3) plan de deploiement priorise sur 18 mois, (4) objectif de repartition ideale entre revenus actifs et passifs a [horizon], (5) indicateurs de suivi mensuel par source de revenus." },
  { id: "s4-087", category: "coach-sportif-independant", title: "Developpement de partenariats medico-sportifs", content: "Tu es un expert en developpement de partenariats pour les coachs sportifs specialises. Concois une strategie de developpement de partenariats avec des professionnels de sante pour un coach sportif. Analyse : (1) identification des partenaires medicaux les plus generateurs de clients qualifies - kinesitherapeutes, medecins du sport, osteopathes, nutritionnistes, (2) valeur apportee a chaque partenaire medical - suivi du patient entre les consultations, resultats mesurables, complementarite, (3) processus de construction du partenariat - approche, presentation, formalisation, suivi, (4) protocoles de co-prise en charge adaptes a chaque pathologie ou objectif de sante, (5) communication du partenariat pour attirer des clients via les reseaux medicaux." },
  { id: "s4-088", category: "coach-sportif-independant", title: "Strategie de tarification et de packages", content: "Tu es un expert en strategie tarifaire pour les coachs sportifs independants. Concois une architecture tarifaire complete permettant d'optimiser le CA par client et de reduire la resistance a l'achat. Construis : (1) analyse de la valeur reelle apportee vs la valeur percue pour justifier une revalorisation tarifaire, (2) structure de 3 packages - starter, transform, elite - avec contenu precis, tarif et promesse de resultat associee, (3) strategie d'ancrage tarifaire pour valoriser l'offre principale, (4) politique de facturation optimale - a la seance vs forfait mensuel vs programme - avec analyse comparative de l'impact sur le CA et la retention, (5) processus de presentation de l'offre pour maximiser le taux de transformation lors du premier entretien." },
  { id: "s4-089", category: "coach-sportif-independant", title: "Plan de developpement des resultats et temoignages", content: "Tu es un expert en preuve sociale et marketing par les resultats pour les coachs sportifs. Concois un systeme complet de generation et de capitalisation des resultats clients. Inclus : (1) systeme de mesure et de documentation des progres clients - indicateurs quantitatifs et qualitatifs, frequence, outils, (2) processus de collecte des temoignages et etudes de cas - timing optimal, questions a poser, formats (texte, video, donnees), (3) strategie d'utilisation des resultats en marketing - landing page, reseaux sociaux, prospection, devis, (4) programme de mise en avant des clients transformes - role d'ambassadeurs, participation au contenu, parrainage, (5) construction d'un portfolio de succes structure par profil client et objectif pour maximiser l'identification des prospects." },
  { id: "s4-090", category: "coach-sportif-independant", title: "Gestion de la transition vers un modele hybride", content: "Tu es un expert en transformation business pour les coachs sportifs en croissance. Concois un plan de transition vers un modele hybride presentiel/digital permettant de doubler le CA sans augmenter proportionnellement le temps de travail. Analyse : (1) audit du temps actuel par activite - coaching, admin, marketing, deplacements - et identification des heures a liberer, (2) selection des clients a migrer vers le digital vs ceux a conserver en presentiel selon leurs caracteristiques, (3) processus de migration des clients presentiel vers le digital - communication, adaptation de l'offre, ajustement tarifaire, (4) organisation hebdomadaire optimale du temps entre les deux canaux, (5) projection de l'impact sur le CA, le temps libre et la satisfaction client a 6, 12 et 24 mois." },
  { id: "s4-091", category: "agence-immobiliere", title: "Strategie de captation de mandats exclusifs", content: "Tu es un expert en developpement commercial pour les agences immobilieres independantes. Concois une strategie complete pour augmenter le taux de mandats exclusifs de [X]% actuel a [Y]% cible. Analyse : (1) diagnostic des freins actuels a l'exclusivite - arguments des vendeurs, concurrence, manque de confiance, (2) construction d'une proposition de valeur de l'exclusivite irresistible - engagement chiffre sur les delais, services premium inclus, communication differenciante, (3) argumentaire de closing specifique pour convertir un mandat simple en mandat exclusif, (4) process de suivi intensif d'un mandat exclusif pour justifier la confiance accordee, (5) impact financier d'une hausse du taux d'exclusivite sur le CA de l'agence - projection sur 12 mois." },
  { id: "s4-092", category: "agence-immobiliere", title: "Developpement d'une strategie digitale et SEO local", content: "Tu es un expert en marketing digital pour les agences immobilieres independantes. Concois une strategie digitale complete pour une agence immobiliere basee a [ville]. Objectif : devenir la reference locale sur Google pour les recherches immobilieres du secteur. Construis : (1) strategie SEO local - mots-cles prioritaires, pages a creer, optimisation technique, Google My Business, (2) strategie de contenu - articles de blog sur le marche local, guides de quartier, analyses de prix - pour dominer le referencement longue traine, (3) strategie reseaux sociaux - LinkedIn pour le B2B et les investisseurs, Instagram pour les biens premium, Facebook pour les particuliers locaux, (4) campagnes d'acquisition payante - Google Ads et Meta Ads - avec ciblage, messages et budgets optimaux, (5) systeme de mesure et d'optimisation mensuel." },
  { id: "s4-093", category: "agence-immobiliere", title: "Strategie de developpement investisseurs", content: "Tu es un expert en developpement commercial pour les agences immobilieres orientees investissement. Concois une strategie complete de developpement d'une clientele d'investisseurs immobiliers sur le secteur de [ville]. Analyse : (1) segmentation des investisseurs cibles - debutants, confirmes, professionnels - avec besoins specifiques et approche adaptee, (2) offre de services dediee aux investisseurs - sourcing off-market, analyse de rentabilite, accompagnement complet, gestion locative, (3) canaux d'acquisition - clubs d'investisseurs, reseaux entrepreneurs, LinkedIn, evenements patrimoniaux, (4) systeme de production de contenus expert sur l'investissement immobilier local pour attirer les investisseurs qualifies, (5) construction d'un reseau de partenaires complementaires - gestionnaires, notaires, CGP, courtiers - pour proposer une solution complete." },
  { id: "s4-094", category: "agence-immobiliere", title: "Optimisation du processus de vente", content: "Tu es un expert en optimisation commerciale pour les agences immobilieres. Analyse le processus de vente actuel et construis un plan d'optimisation pour augmenter le taux de transformation vendeur/acheteur de [X]% a [Y]%. Analyse : (1) cartographie du processus actuel - etapes, durees, taux de transformation a chaque etape, points de friction, (2) optimisation de la qualification acheteurs - methode, questions cles, criteres de priorisation, (3) strategie de matching rapide entre mandats et acheteurs qualifies, (4) techniques de facilitation de la decision d'achat - visite optimisee, presentation du bien, creation d'urgence legitime, (5) processus de suivi post-visite et de traitement des objections les plus frequentes." },
  { id: "s4-095", category: "agence-immobiliere", title: "Developpement de l'activite gestion locative", content: "Tu es un expert en developpement de nouvelles lignes de revenus pour les agences immobilieres. Concois une strategie complete de developpement d'une activite de gestion locative. Analyse : (1) modele economique de la gestion locative - structure tarifaire, charges, marges, seuil de rentabilite par nombre de lots geres, (2) offre de gestion locative differenciante - services premium, reporting digital, garantie loyers impayes, accompagnement travaux, (3) strategie de captation des premiers mandats de gestion - ciblage des bailleurs, argumentation, processus de transition, (4) organisation operationnelle - logiciel de gestion, process, relations locataires, (5) projection du CA recurrent genere a 50, 100, 200 lots geres et impact sur la valeur de l'agence." },
  { id: "s4-096", category: "agence-immobiliere", title: "Strategie de recrutement et de developpement des negociateurs", content: "Tu es un expert en management et developpement RH pour les agences immobilieres. Concois un systeme complet de recrutement et de developpement des negociateurs pour une agence independante. Inclus : (1) profil ideal du negociateur selon le positionnement de l'agence - competences, experience, valeurs, (2) processus de recrutement - sourcing, selection, entretiens, tests, (3) plan d'integration sur 90 jours - formation, accompagnement, objectifs progressifs, (4) systeme de remuneration motivant - structure fixe/variable, paliers de commissionnement, primes, (5) plan de developpement des competences et de management hebdomadaire pour maximiser la performance de chaque negociateur." },
  { id: "s4-097", category: "agence-immobiliere", title: "Analyse et optimisation du portefeuille de mandats", content: "Tu es un expert en gestion du portefeuille commercial pour les agences immobilieres. Concois un systeme d'analyse et d'optimisation du portefeuille de mandats actif. Construis : (1) tableau de bord de pilotage du portefeuille - age des mandats, prix vs marche, taux de visite, niveau d'activite par mandat, (2) processus de revue mensuelle des mandats dormants - criteres d'alerte, actions correctives, decision de maintien ou d'abandon, (3) strategie de reduction des delais de vente - actions marketing ciblees par type de blocage (prix, presentation, ciblage), (4) politique de tarification dynamique - quand et comment recommander une revision de prix, argumentation, (5) impact d'une reduction de [X] jours du delai moyen de vente sur le CA annuel de l'agence." },
  { id: "s4-098", category: "agence-immobiliere", title: "Developpement d'une marque employeur forte", content: "Tu es un expert en marque employeur pour les acteurs de l'immobilier. Concois une strategie de developpement de la marque employeur pour une agence immobiliere independante souhaitant attirer les meilleurs negociateurs du marche. Analyse : (1) audit de l'attractivite actuelle de l'agence comme employeur - culture, remuneration, perspectives, reputation, (2) definition de la proposition de valeur employeur - ce qui rend unique de travailler dans cette agence, (3) strategie de communication de la marque employeur - LinkedIn, job boards, temoignages collaborateurs, (4) culture d'entreprise a developper - valeurs, rituels, cohesion, reconnaissance, (5) programme de fidelisation des meilleurs negociateurs - remuneration, autonomie, participation, perspectives d'evolution." },
  { id: "s4-099", category: "agence-immobiliere", title: "Strategie de developpement des avis et recommandations", content: "Tu es un expert en reputation digitale pour les agences immobilieres. Concois un systeme complet de collecte et de valorisation des avis clients pour une agence immobiliere. Construis : (1) processus systematise de collecte d'avis - timing optimal, canal (SMS/email), message personnalise, objectif par negociateur, (2) strategie de reponse aux avis - tous les avis, meme negatifs - avec modeles de reponse adaptes a chaque type d'avis, (3) valorisation des avis dans toutes les communications - site, reseaux, emails, devis, (4) programme de temoignages video - comment les obtenir, les filmer simplement, les diffuser, (5) impact mesurable sur le taux de conversion des prospects et objectif de volume d'avis a atteindre." },
  { id: "s4-100", category: "agence-immobiliere", title: "Plan de developpement sur 3 ans", content: "Tu es un expert en strategie de developpement pour les agences immobilieres independantes. Construis un plan de developpement strategique sur 3 ans pour une agence souhaitant passer de [CA actuel] a [CA cible] avec [equipe actuelle]. Analyse : (1) audit strategique complet - forces, faiblesses, opportunites de marche, menaces concurrentielles, (2) axes de croissance prioritaires selon le contexte - geographie, services complementaires, recrutement, digital, (3) plan operationnel annee par annee avec objectifs chiffres, investissements necessaires et responsabilites, (4) gestion des risques - scenarios adverses et plans de contingence, (5) indicateurs cles de performance par axe de developpement et cadence de revue strategique." },
  { id: "s4-101", category: "journaliste-independant", title: "Strategie de diversification des sources de revenus", content: "Tu es un expert en developpement business pour les journalistes et createurs de contenu independants. Concois une strategie complete de diversification des revenus pour un journaliste freelance dont [X]% des revenus dependent de [X] medias. Analyse : (1) audit des competences monetisables au-dela de la pige - redaction corporate, formation, conseil editorial, podcasting, book, (2) evaluation du potentiel de chaque nouvelle source de revenus - marche, tarification, temps necessaire, compatibilite deontologique, (3) plan de developpement priorise de 3 nouvelles sources sur 18 mois, (4) strategie pour reduire la dependance a un seul ou deux medias en developpant le portefeuille de commanditaires, (5) projection financiere avant/apres diversification avec objectifs de repartition cible." },
  { id: "s4-102", category: "journaliste-independant", title: "Construction d'une expertise et d'une autorite sur une niche", content: "Tu es un expert en personal branding pour les journalistes specialises. Concois une strategie complete pour devenir la reference journalistique reconnue sur la thematique [sujet]. Analyse : (1) audit de l'expertise actuelle et identification des gaps a combler pour etre incontournable, (2) strategie de veille et de production de contenus experts - formats, frequence, canaux, (3) developpement d'un reseau de sources de premier plan sur la thematique - chercheurs, decideurs, praticiens, (4) plan de visibilite dans les medias de reference de la niche - pitchs cibles, tribunes, interviews, (5) construction d'actifs durables - newsletter specialisee, livre blanc, book - qui consolident l'autorite sur le long terme." },
  { id: "s4-103", category: "journaliste-independant", title: "Developpement d'une newsletter a revenus", content: "Tu es un expert en monetisation de l'information pour les journalistes independants. Concois une strategie complete de creation et de monetisation d'une newsletter specialisee sur [thematique]. Construis : (1) positionnement editorial unique - angle, promesse, rythme, ton - qui justifie l'abonnement payant, (2) modele economique - gratuit vs freemium vs payant - avec analyse du potentiel de revenus selon les scenarios, (3) strategie de croissance de la base abonnes - canaux, contenus de conversion, partenariats, (4) offre premium differenciante - acces archives, veille dediee, acces sources, reseau abonnes, (5) plan de developpement sur 12 mois - objectifs d'abonnes, de taux de conversion, de CA - avec milestones et leviers d'action." },
  { id: "s4-104", category: "journaliste-independant", title: "Strategie de valorisation commerciale de l'expertise", content: "Tu es un expert en positionnement commercial pour les journalistes et experts medias. Concois une strategie pour valoriser et commercialiser l'expertise d'un journaliste specialise aupres d'acteurs non mediatiques. Analyse : (1) identification des competences monnayables en dehors du journalisme - analyse sectorielle, veille strategique, redaction de rapports, formation, conseil en communication, (2) ciblage des clients potentiels - entreprises du secteur couvert, cabinets de conseil, think tanks, institutions, (3) construction de l'offre de services avec tarification adaptee au marche B2B, (4) strategie de conversion de la notoriete journalistique en credibilite commerciale, (5) gestion des conflits d'interets potentiels et cadre deontologique a definir." },
  { id: "s4-105", category: "journaliste-independant", title: "Plan de negociation des conditions avec les medias", content: "Tu es un expert en negociation commerciale pour les freelances et independants. Concois un guide complet de negociation des conditions de collaboration avec les medias pour un journaliste independant. Inclus : (1) audit des conditions actuelles - tarifs pratiques vs marche, droits accordes, delais de paiement, exclusivites - et identification des marges de negociation, (2) strategie de negociation adaptee a chaque type de media - presse nationale, presse regionale, medias digitaux, B2B, (3) tactiques de valorisation de son profil pour augmenter son pouvoir de negociation, (4) clauses contractuelles essentielles a exiger - droits d'auteur, delais de paiement, kill fees, (5) gestion des situations de blocage et alternatives a developper pour ne pas dependre d'un seul commanditaire." },
  { id: "s4-106", category: "journaliste-independant", title: "Developpement d'une activite de formation", content: "Tu es un expert en developpement d'activite pedagogique pour les journalistes. Concois une offre de formation complete pour un journaliste souhaitant transmettre son expertise. Analyse : (1) identification des competences les plus demandees par les cibles potentielles - ecoles de journalisme, entreprises, associations professionnelles, particuliers, (2) catalogue de formations a construire - writing, investigation, fact-checking, interview, storytelling - avec durees et formats adaptes a chaque cible, (3) tarification des formations en presentiel et en ligne selon le marche, (4) strategie de developpement commercial - appels d'offres, plateformes de formation, LinkedIn, reseaux journalistes, (5) options de certification et labels qualite pertinents pour credibiliser l'offre de formation." },
  { id: "s4-107", category: "journaliste-independant", title: "Strategie de gestion et de developpement du reseau de sources", content: "Tu es un expert en intelligence relationnelle pour les journalistes d'investigation. Concois un systeme complet de gestion et de developpement du reseau de sources pour un journaliste specialise sur [thematique]. Inclus : (1) cartographie des sources actuelles - niveau de confiance, frequence de contact, valeur informationnelle - et identification des gaps, (2) strategie de developpement de nouvelles sources de qualite dans les milieux cles de la thematique, (3) systeme de maintien et de nurturing du reseau dans le temps - frequence de contact, canaux, valeur apportee aux sources, (4) gestion de la confidentialite et de la protection des sources - protocoles, outils securises, (5) utilisation ethique du reseau pour developper des exclusivites et consolider le positionnement editorial." },
  { id: "s4-108", category: "journaliste-independant", title: "Developpement d'une offre de fact-checking et verification", content: "Tu es un expert en developpement de services editoriaux specialises. Concois une offre de service de fact-checking et de verification d'information pour un journaliste independant. Analyse : (1) marche de la verification en France - acteurs existants, besoins non couverts, positionnement differenciant possible, (2) offre de service structuree - fact-checking ponctuel, veille informationnelle, formation aux medias, certification de contenu, (3) clients potentiels - medias, entreprises sensibles a la desinformation, associations, institutions, (4) methodologie et processus de verification documentes pour credibiliser l'offre, (5) modele economique - a la mission, abonnement, formation - avec projection de revenus." },
  { id: "s4-109", category: "journaliste-independant", title: "Strategie de propriete intellectuelle et droits d'auteur", content: "Tu es un expert juridique specialise dans les droits des journalistes et createurs de contenu. Concois une strategie complete de gestion et de valorisation des droits d'auteur pour un journaliste freelance. Analyse : (1) audit du patrimoine intellectuel existant - articles, reportages, photos, enquetes - et de leur exploitation actuelle, (2) strategie de negociation des droits dans les contrats avec les medias - cession partielle vs totale, duree, territoire, formats, (3) monetisation des droits non cedes - revente a d'autres medias, adaptation en livre, traduction, creation de cours, (4) organisation et archivage du patrimoine intellectuel pour faciliter sa reutilisation, (5) veille sur les utilisations non autorisees de ses oeuvres et processus de reclamation." },
  { id: "s4-110", category: "journaliste-independant", title: "Plan de transition vers l'entrepreneuriat editorial", content: "Tu es un expert en entrepreneuriat pour les journalistes. Concois un plan de transition vers un modele d'entrepreneuriat editorial pour un journaliste freelance souhaitant prendre son independance editoriale totale. Analyse : (1) options d'entrepreneuriat editorial - media en ligne, podcast premium, newsletter payante, agence de contenu - avec analyse comparative, (2) conditions prealables a reunir - audience, reseau, capital, competences business, (3) modele economique du projet choisi - sources de revenus, structure des couts, seuil de rentabilite, (4) plan de financement - fonds propres, crowdfunding, subventions press, business angels, (5) plan de transition progressive de la pige vers l'independance totale sur 24 mois avec gestion du risque financier." },
  { id: "s4-111", category: "courtier-credit", title: "Strategie de developpement reseau apporteurs d'affaires", content: "Tu es un expert en developpement commercial pour les courtiers en credit independants. Concois une strategie complete de developpement d'un reseau d'apporteurs d'affaires. Identifie et active : (1) cartographie exhaustive des apporteurs potentiels - agents immobiliers, notaires, CGP, constructeurs, promoteurs, marchands de biens - avec leur volume d'affaires potentiel et leur mode de fonctionnement, (2) proposition de valeur de chaque type d'apporteur - ce qu'ils gagnent concretement a travailler avec moi, (3) conditions du partenariat - commission, delais, qualite de service, communication, (4) systeme de suivi et d'entretien du reseau - relances, reporting, evenements, (5) tableau de bord du CA genere par apporteur et seuil de rentabilite de chaque relation." },
  { id: "s4-112", category: "courtier-credit", title: "Optimisation du taux de transformation dossiers", content: "Tu es un expert en optimisation commerciale pour les courtiers en credit. Concois un plan d'optimisation du taux de transformation des dossiers de [X]% a [Y]%. Analyse : (1) cartographie du processus actuel - etapes, durees, taux de chute a chaque etape et causes, (2) qualification des prospects amelioree - criteres, questions, outils - pour reduire les dossiers non financables, (3) optimisation du montage dossier - checklist, outils, formation, presentation aux banques, (4) strategie de negociation bancaire - panel de banques, argumentaires differencies, timing, (5) processus de suivi client pendant l'instruction pour maintenir l'engagement jusqu'a la signature." },
  { id: "s4-113", category: "courtier-credit", title: "Developpement d'une offre de credit professionnel", content: "Tu es un expert en developpement d'offres pour les courtiers independants. Concois une strategie de developpement sur le segment du credit professionnel (TPE/PME) en complement du credit immobilier particulier. Analyse : (1) specificites du marche credit pro - types de financements, interlocuteurs, processus de decision, banques specialisees, (2) formation et certification necessaires pour intervenir legalement sur ce segment, (3) segmentation des clients pro a adresser en priorite - secteurs, tailles, besoins types, (4) partenariats a developper - experts-comptables, avocats d'affaires, chambres de commerce, (5) modele economique du credit pro vs immobilier particulier - commissions, durees de traitement, rentabilite horaire comparee." },
  { id: "s4-114", category: "courtier-credit", title: "Strategie de positionnement expert sur le marche local", content: "Tu es un expert en strategie de positionnement pour les courtiers independants. Concois une strategie complete pour devenir la reference courtage credit sur le marche de [ville/secteur]. Analyse : (1) audit concurrentiel local - acteurs en presence (banques directes, franchises, independants), leurs forces et faiblesses, espaces disponibles, (2) positionnement differenciant - specialisation par profil client (primo-accedants, investisseurs, profils atypiques), service premium, expertise locale, (3) strategie de visibilite locale - SEO local, presence reseaux, evenements, (4) developpement d'une expertise editoriale sur le marche immobilier local - analyses de prix, guides d'achat, guides d'investissement, (5) objectifs de notoriete et indicateurs de mesure sur 12 mois." },
  { id: "s4-115", category: "courtier-credit", title: "Systeme de pilotage commercial et financier", content: "Tu es un expert en gestion d'entreprise pour les courtiers independants. Concois un systeme complet de pilotage commercial et financier pour un courtier en credit. Construis : (1) tableau de bord commercial - pipeline par stade, taux de transformation, delais moyens, CA previsionnel, CA securise, (2) tableau de bord financier - CA encaisse, CA a encaisser, charges, resultat, tresorerie previsionnelle, (3) indicateurs d'activite hebdomadaires - nombre de nouveaux contacts, rendez-vous, dossiers deposes, accords obtenus, (4) processus de revue mensuelle de l'activite - analyse des ecarts, decisions correctives, ajustement des objectifs, (5) outils recommandes pour tenir ces tableaux de bord en moins de 2 heures par semaine." },
  { id: "s4-116", category: "courtier-credit", title: "Developpement d'une activite de conseil patrimonial", content: "Tu es un expert en developpement de services financiers complementaires. Concois une strategie d'elargissement de l'offre vers le conseil patrimonial pour un courtier en credit independant. Analyse : (1) certifications et habilitations necessaires - IAS, CIF, carte professionnelle - avec plan d'obtention, (2) offre complementaire a construire - assurance emprunteur, assurance habitude, prevoyance - en coherence avec l'activite credit, (3) modele economique - commissions, honoraires, recurrence, (4) strategie de cross-sell aupres des clients credit existants - timing, argumentaire, processus, (5) risques reglementaires et ethiques a gerer et cadre de conformite a mettre en place." },
  { id: "s4-117", category: "courtier-credit", title: "Strategie de communication et d'education financiere", content: "Tu es un expert en content marketing financier pour les courtiers independants. Concois une strategie de contenu educatif pour un courtier en credit visant a attirer des prospects qualifies et a reduire leur anxiete face au credit immobilier. Construis : (1) cartographie des questions et inquietudes des prospects a chaque etape de leur parcours - preparation, recherche, achat, financement, (2) plan de contenu educatif - articles, videos, infographies, simulateurs - repondant a chaque question, (3) sequence d'email nurturing pour accompagner les prospects dans leur reflexion, (4) strategie de distribution - SEO, reseaux sociaux, partenaires - pour maximiser la visibilite du contenu, (5) systeme de conversion du lecteur en prospect qualifie - lead magnet, calculette, rendez-vous gratuit." },
  { id: "s4-118", category: "courtier-credit", title: "Gestion de la conformite reglementaire", content: "Tu es un expert en conformite reglementaire pour les intermediaires en operations de banque. Concois un systeme complet de gestion de la conformite reglementaire pour un IOBSP independant. Inclus : (1) cartographie des obligations reglementaires cles - ORIAS, DIC, fiche de renseignements, devoir de conseil, RGPD, (2) processus et outils pour documenter le respect de chaque obligation - templates, checklists, archivage, (3) formation continue obligatoire - volume requis, organismes reconnus, organisation dans le calendrier, (4) gestion des controles ACPR - preparation, documents a tenir a disposition, procedures a formaliser, (5) veille reglementaire - sources, frequence, processus de mise a jour des pratiques." },
  { id: "s4-119", category: "courtier-credit", title: "Developpement d'un modele de franchise ou de reseau", content: "Tu es un expert en developpement de reseaux pour les courtiers independants. Analyse la faisabilite et concois un plan de developpement d'un reseau de courtiers sous ma marque pour un courtier souhaitant capitaliser sur son modele et ses outils. Analyse : (1) conditions prealables - volume d'affaires minimal, systemes documentes, outils proprietaires, marque etablie, (2) modele juridique adapte - franchise, reseau de mandataires, portage - avec analyse comparative, (3) proposition de valeur pour les courtiers rejoignant le reseau - formation, outils, apport d'affaires, marque, (4) modele economique du reseau - fees d'entree, redevances, partage des commissions, (5) plan de developpement du reseau sur 3 ans avec objectifs, investissements et ROI." },
  { id: "s4-120", category: "courtier-credit", title: "Strategie de retention et de fidelisation clients", content: "Tu es un expert en fidelisation pour les prestataires de services financiers. Concois un systeme complet de fidelisation et de developpement du CA sur la base clients existants pour un courtier en credit. Construis : (1) cartographie du cycle de vie client post-credit - opportunites de contact et de service dans les 5 a 10 ans suivant l'operation, (2) programme de suivi personnalise - jalons de contact, evenements declencheurs (renegociation, rachat, nouveau projet), (3) offres de services complementaires adaptees a chaque moment du cycle - rachat de credit, credit travaux, investissement locatif, (4) systeme de recommandation active - comment transformer chaque client satisfait en source de recommandations actives, (5) indicateurs de valeur a vie client et impact d'une augmentation de la retention sur le CA recurrent." },
  { id: "s4-121", category: "marchand-de-biens", title: "Analyse de la rentabilite d'une operation complexe", content: "Tu es un expert en analyse financiere immobiliere pour les marchands de biens professionnels. Realise une analyse de rentabilite complete d'une operation de marchand de biens. Donnees : bien situe [adresse], surface [X]m², prix demande [montant], etat [description], zone [caracteristiques]. Calcule et analyse : (1) scenario de travaux optimiste/realiste/pessimiste avec budgets detailles par poste, (2) prix de revient complet - acquisition, notaire, travaux, portage, commercialisation, (3) valeur de revente selon 3 hypotheses de marche avec analyse de sensibilite, (4) marges nettes et TRI selon les scenarios et la duree d'operation, (5) points de vigilance, clauses suspensives a integrer et seuil de go/no-go decisionnel." },
  { id: "s4-122", category: "marchand-de-biens", title: "Strategie de sourcing off-market", content: "Tu es un expert en strategie d'acquisition pour les marchands de biens professionnels. Concois un systeme complet de sourcing de biens off-market pour un marchand de biens actif sur [zone geographique]. Construis : (1) cartographie des sources d'opportunites off-market - notaires succession, administrateurs de biens, syndics, gestionnaires de patrimoine, mairies, (2) approche specifique et message adapte a chaque source pour maximiser les remontees, (3) systeme de veille automatisee - alertes PAP/LBC, monitoring PO, veille succession, (4) processus de qualification rapide d'une opportunite - criteres de go/no-go, analyse preliminaire en moins d'une heure, (5) systeme de suivi des contacts et de relance pour maintenir le flux d'opportunites dans le temps." },
  { id: "s4-123", category: "marchand-de-biens", title: "Strategie de financement et d'optimisation du levier", content: "Tu es un expert en ingenierie financiere pour les marchands de biens. Concois une strategie de financement optimale pour maximiser le rendement des fonds propres sur un portefeuille d'operations. Analyse : (1) panel bancaire optimal a constituer - banques specialisees MB, banques regionales, etablissements alternatifs - avec criteres de selection et approche, (2) structure de financement ideale par type d'operation - acquisition+travaux, division, surelevation, (3) optimisation du levier - taux d'emprunt maximal acceptable selon la marge cible et le risque, (4) alternatives au financement bancaire - crowdlending, marchand de biens institutionnel, apporteurs de fonds propres, (5) gestion du risque de refinancement et strategie en cas de depassement de delai ou de cout." },
  { id: "s4-124", category: "marchand-de-biens", title: "Developpement d'une strategie de division parcellaire", content: "Tu es un expert en operations de decoupage et de division pour les marchands de biens. Concois un guide complet pour developper une activite de division de biens immobiliers. Analyse : (1) criteres d'identification d'un bien divisible - surface, configuration, regles d'urbanisme, charges, (2) processus d'instruction d'une division - geometre, declaration prealable ou PC, modificatif au RCP, (3) risques specifiques aux operations de division - delais administratifs, copropriete, voisinage, recours, (4) analyse financiere comparative division vs vente en l'etat - impact sur le prix de vente total, duree operation, complexite, (5) commercial de la revente - faut-il vendre divise ou apres reunification des lots, strategie selon le marche local." },
  { id: "s4-125", category: "marchand-de-biens", title: "Gestion juridique et fiscale des operations", content: "Tu es un expert en droit et fiscalite immobiliere pour les marchands de biens professionnels. Concois un cadre complet de gestion juridique et fiscale des operations de marchand de biens. Inclus : (1) choix de la structure juridique optimale - SAS, SASU, SCI IS - selon le volume d'operations et les objectifs patrimoniaux, (2) regime fiscal specifique des marchands de biens - TVA sur marge, exoneration droits de mutation, conditions d'application, (3) contrats d'acquisition a securiser - conditions suspensives essentielles, delais de regularisation, clauses de sortie, (4) gestion des risques juridiques specifiques - garanties vices caches, responsabilite decennale, litiges acquereurs, (5) strategie d'optimisation fiscale des distributions et de la remuneration du dirigeant." },
  { id: "s4-126", category: "marchand-de-biens", title: "Developpement d'un portefeuille locatif en parallele", content: "Tu es un expert en strategie patrimoniale pour les marchands de biens. Concois une strategie de constitution d'un patrimoine locatif en parallele de l'activite marchand de biens pour creer des revenus recurrents. Analyse : (1) arbitrage entre operations MB et conservation de certains biens en locatif selon les conditions de marche, (2) structure juridique optimale pour la detention du parc locatif - SCI IS vs SCI IR vs detention directe, (3) selection des biens a conserver selon leur rendement, leur potentiel de valorisation et leur facilite de gestion, (4) financement de la constitution du parc - autofinancement sur les marges MB, emprunt, (5) strategie de gestion du parc - gestion directe vs delegation, et projection de revenus passifs sur 5 et 10 ans." },
  { id: "s4-127", category: "marchand-de-biens", title: "Strategie de developpement sur les marches secondaires", content: "Tu es un expert en developpement geographique pour les marchands de biens. Concois une strategie d'expansion sur de nouveaux marches geographiques en dehors de la zone principale d'activite. Analyse : (1) methode d'identification et de selection des marches secondaires attractifs - dynamisme, prix d'entree, rendements, concurrence MB, (2) constitution du reseau local necessaire - agents immobiliers, notaires, artisans, gestionnaires, (3) adaptation de la strategie operationnelle a distance - sourcing, suivi chantier, commercialisation, (4) risques specifiques des operations hors zone - connaissance marche insuffisante, reseau limite, gestion a distance, (5) criteres de validation d'un premier test sur un nouveau marche et plan de montee en puissance progressive." },
  { id: "s4-128", category: "marchand-de-biens", title: "Optimisation de la commercialisation des biens renoves", content: "Tu es un expert en commercialisation immobiliere pour les marchands de biens. Concois une strategie complete d'optimisation de la commercialisation des biens renoves pour maximiser le prix de vente et reduire les delais. Analyse : (1) home staging professionnel - impact sur le prix et les delais, prestataires recommandes, budget optimal, (2) strategie de prix de mise en vente - prix d'appel vs prix plafond, timing de la baisse eventuelle, (3) canaux de commercialisation a activer et prioriser - agences, portails, reseau perso, notaires, (4) qualite des visuels et de la presentation - photos professionnelles, 3D, video, visite virtuelle, (5) processus de qualification des acquereurs pour eviter les pertes de temps et les transactions qui capoter." },
  { id: "s4-129", category: "marchand-de-biens", title: "Developpement d'operations de surelevation", content: "Tu es un expert en operations de surelevation pour les marchands de biens innovants. Concois un guide complet pour developper une activite de surelevation d'immeubles. Analyse : (1) identification des immeubles surselevables - criteres techniques, urbanistiques, et de copropriete, (2) processus d'achat du droit a surelever aupres de la copropriete - approche des syndics, valorisation du droit, negociation, (3) faisabilite technique - structures legeres, ossature bois, delais de construction, (4) montage financier specifique - cout au m² de creation, prix de revente espere, marges, (5) gestion de la copropriete pendant et apres les travaux - communication, responsabilites, remise en etat des parties communes." },
  { id: "s4-130", category: "marchand-de-biens", title: "Strategie de sortie et de transmission de l'activite", content: "Tu es un expert en strategie de sortie pour les marchands de biens professionnels. Concois une strategie complete de preparation a la sortie ou a la transmission de l'activite de marchand de biens. Analyse : (1) valorisation de l'activite MB - actifs, reseau, portefeuille d'operations en cours, competences, (2) options de sortie - cession a un investisseur, association avec un partenaire, transmission a un collaborateur, (3) optimisation fiscale de la sortie selon la structure juridique retenue, (4) preparation de l'activite pour la rendre transmissible - documentation des processus, independance vis-a-vis du dirigeant, (5) plan de transition sur 2 a 3 ans pour maximiser la valeur de cession tout en maintenant la performance operationnelle." },
  { id: "s4-131", category: "conciergerie-lcd", title: "Strategie de developpement du portefeuille proprietaires", content: "Tu es un expert en developpement commercial pour les conciergeries Airbnb professionnelles. Concois une strategie complete pour developper le portefeuille de proprietaires partenaires de [X] biens actuels a [Y] biens en 18 mois. Analyse : (1) segmentation des proprietaires cibles - investisseurs avec plusieurs biens, proprietaires residences secondaires, heritiers de biens vides, (2) canaux d'acquisition specifiques a chaque profil - LinkedIn investisseurs, notaires, administrateurs de biens, forums investissement locatif, (3) proposition de valeur chiffree - simulation de revenus vs gestion en direct, economie de temps, tranquillite, (4) processus de signature du contrat de gestion - etapes, documents, conditions, (5) objectifs par canal et tableau de bord d'acquisition mensuel." },
  { id: "s4-132", category: "conciergerie-lcd", title: "Optimisation du revenu par logement", content: "Tu es un expert en revenue management pour les hebergements touristiques. Concois une strategie complete d'optimisation du revenu par logement pour une conciergerie de location courte duree. Construis : (1) strategie de tarification dynamique - outils recommandes, parametres a ajuster, frequence de mise a jour, (2) optimisation du calendrier de disponibilite - politique de duree minimale de sejour, gestion des trous, last minute, (3) strategie de distribution multi-plateformes - Airbnb, Booking, Abritel, site direct - avec priorisation et gestion du channel manager, (4) optimisation des fiches annonces - titre, description, photos, equipements differenciants, (5) impact d'une amelioration de [X] points du taux d'occupation et du RevPAR sur le CA de la conciergerie." },
  { id: "s4-133", category: "conciergerie-lcd", title: "Developpement d'une offre de services premium", content: "Tu es un expert en strategie de montee en gamme pour les acteurs de la conciergerie. Concois une strategie de developpement d'une offre de services premium pour differencier la conciergerie et augmenter la valeur par logement gere. Analyse : (1) services a valeur ajoutee a developper - accueil personnalise, panier de bienvenue, linge de luxe, services conciergerie voyageur (taxi, restaurant, activites), (2) monetisation des services additionnels - inclus dans la commission ou factures en supplement, (3) impact sur le positionnement et les tarifs des logements - argument de vente pour recruter de nouveaux proprietaires, (4) operationnalisation - prestataires, logistique, formation de l'equipe, (5) communication aux voyageurs pour generer des avis 5 etoiles et des reservations directes." },
  { id: "s4-134", category: "conciergerie-lcd", title: "Strategie de gestion et de fidelisation de l'equipe", content: "Tu es un expert en management pour les conciergeries en croissance. Concois un systeme complet de gestion et de fidelisation d'une equipe d'agents de menage et de conciergerie. Inclus : (1) recrutement - criteres de selection, processus, tests, (2) formation initiale et continue - protocoles de menage, standards de qualite, communication avec voyageurs, (3) systeme de remuneration motivant et equitable - fixe, variable, primes qualite, (4) outils de management operationnel - applications de planning, communication, controle qualite, (5) gestion des remplacements et de la flexibilite - reseau de backup, astreintes, processus de remplacement d'urgence." },
  { id: "s4-135", category: "conciergerie-lcd", title: "Developpement d'une strategie de reservations directes", content: "Tu es un expert en marketing direct pour les hebergements touristiques. Concois une strategie complete pour developper les reservations directes et reduire la dependance aux plateformes. Construis : (1) developpement d'un site de reservation direct - outils, fonctionnalites essentielles, optimisation pour la conversion, (2) strategie de constitution d'une base de voyageurs fideles - collecte emails, RGPD, segmentation, (3) programme de fidelisation voyageurs - reductions recurrence, early bird, parrainage, (4) marketing par email aux anciens voyageurs - sequences de reactivation, offres saisonnieres, (5) projection d'economie sur les commissions plateformes et impact sur la rentabilite a [X]% de reservations directes." },
  { id: "s4-136", category: "conciergerie-lcd", title: "Strategie de conformite reglementaire locale", content: "Tu es un expert en reglementation des locations courtes durees en France. Concois un guide de conformite complet pour une conciergerie operant sur [ville]. Analyse : (1) obligations legales specifiques a la ville - numero d'enregistrement, declaration mairie, taxe de sejour, limitation a 120 jours pour residences principales, (2) processus de mise en conformite pour chaque logement gere - etapes, documents, delais, (3) obligations vis-a-vis des proprietaires - information, contrat de mandat, comptes rendus, (4) gestion des controles et des contentieux - risques, procedures de defense, assurances, (5) veille reglementaire - comment anticiper les changements de reglementation et adapter le modele en consequence." },
  { id: "s4-137", category: "conciergerie-lcd", title: "Optimisation des couts et de la rentabilite", content: "Tu es un expert en gestion financiere pour les conciergeries de location courte duree. Concois un systeme d'analyse et d'optimisation de la rentabilite pour une conciergerie gerant [X] logements. Construis : (1) modele economique detaille - revenus par logement, couts directs (menage, linge, consommables), couts indirects, marge par logement et par type de bien, (2) seuil de rentabilite du portefeuille et par logement - les biens sous-performants a identifier et a traiter, (3) leviers d'optimisation des couts - negociation fournisseurs linge, optimisation des tournees menage, mutualisation, (4) politique de tarification des services a l'equilibre - commission optimale selon le type de bien, (5) tableau de bord financier mensuel pour piloter la rentabilite en temps reel." },
  { id: "s4-138", category: "conciergerie-lcd", title: "Strategie de developpement en franchise ou reseau", content: "Tu es un expert en developpement de reseaux pour les acteurs de la conciergerie. Concois un plan de developpement d'un reseau de conciergeries sous licence ou en franchise pour capitaliser sur un modele eprouve. Analyse : (1) conditions prealables - volume minimum, systemes documentes, marque etablie, rentabilite prouvee, (2) modele de reseau adapte - franchise, reseau de licencies, co-entreprise locale, (3) valeur apportee aux membres du reseau - marque, systemes, outils, formation, sourcing, (4) modele economique du reseau - droits d'entree, redevances, accompagnement, (5) plan de developpement geographique sur 3 ans et profil ideal du candidat franchise." },
  { id: "s4-139", category: "conciergerie-lcd", title: "Developpement d'une strategie de contenu et de referencement", content: "Tu es un expert en marketing de contenu pour les acteurs du tourisme et de l'hebergement. Concois une strategie de contenu et de referencement pour une conciergerie souhaitant attirer des proprietaires et des voyageurs en organique. Construis : (1) strategie SEO proprietaires - mots-cles ciblant les proprietaires cherchant a deleguer, contenu a produire, optimisation locale, (2) strategie SEO voyageurs - pour developper les reservations directes, pages de destinations, guides locaux, (3) strategie de blog - sujets, frequence, structure des articles pour maximiser le referencement, (4) distribution du contenu - reseaux sociaux, newsletter, partenariats, (5) systeme de mesure du ROI du contenu - trafic organique, conversions proprietaires, reservations directes generees." },
  { id: "s4-140", category: "conciergerie-lcd", title: "Plan de gestion de crise et resilience operationnelle", content: "Tu es un expert en gestion de risques pour les operateurs de location courte duree. Concois un plan complet de gestion de crise et de resilience pour une conciergerie. Analyse les scenarios : (1) crise reglementaire - interdiction ou limitation severe de la LCD dans la ville d'operation - strategie de pivot vers la location longue duree ou d'autres marches, (2) crise operationnelle - perte d'une equipe de menage, pandemie, greve des transports - protocoles de backup et de continuite, (3) crise reputationnelle - bad buzz sur les reseaux, bad reviews en cascade - processus de reponse et de reconstruction, (4) crise financiere - chute brutale du taux d'occupation, (5) pour chaque scenario : indicateurs d'alerte precoce, protocole de reponse, ressources necessaires, delai de retour a la normale." },
  { id: "s4-141", category: "maitre-oeuvre-btp", title: "Strategie de developpement commercial et de notoriete", content: "Tu es un expert en developpement commercial pour les maitres d'oeuvre independants. Concois une strategie complete de developpement commercial sur 18 mois pour un maitre d'oeuvre base a [ville] specialise en [type de travaux]. Analyse : (1) segmentation des clients cibles les plus rentables - particuliers aises, promoteurs, collectivites, investisseurs - avec approche adaptee a chaque segment, (2) developpement du reseau prescripteur - architectes, notaires, agents immobiliers, coproprietes, gestionnaires de patrimoine - avec processus d'activation, (3) strategie de visibilite digitale - site, reseaux sociaux, Google, etudes de cas, (4) objectifs chiffres par canal et par trimestre, (5) budget commercial et ROI attendu." },
  { id: "s4-142", category: "maitre-oeuvre-btp", title: "Systeme de gestion multi-chantiers", content: "Tu es un expert en organisation et gestion de projets BTP. Concois un systeme complet de pilotage simultane de plusieurs chantiers pour un maitre d'oeuvre independant gerant [X] chantiers en parallele. Construis : (1) outil de planning multi-chantiers - visualisation, mises a jour, alertes, partage avec equipes, (2) systeme de compte-rendu hebdomadaire standardise et rapide a produire pour chaque chantier, (3) processus de gestion des priorites et d'allocation du temps entre les chantiers selon l'urgence et la criticite, (4) tableaux de bord financiers par chantier - avancement physique vs financier, depassements, reste a engager, (5) processus d'escalade pour les situations critiques - qui decide, quand, comment." },
  { id: "s4-143", category: "maitre-oeuvre-btp", title: "Strategie de selection et de gestion des entreprises", content: "Tu es un expert en gestion des sous-traitants et entreprises pour les maitres d'oeuvre. Concois un systeme complet de selection, de gestion et d'evaluation des entreprises intervenantes. Inclus : (1) processus de qualification des entreprises - criteres techniques, financiers, assurantiels, references, (2) consultation optimale - DCE type, criteres de notation, negociation, (3) contractualisation - clauses essentielles, penalites de retard, conditions de paiement, revision des prix, (4) suivi et controle qualite sur chantier - visites, PV de reunion, reserves, levee de reserves, (5) evaluation post-chantier - methode de notation, panel fournisseurs a maintenir et a renouveler." },
  { id: "s4-144", category: "maitre-oeuvre-btp", title: "Developpement d'une specialisation en renovation energetique", content: "Tu es un expert en strategie de specialisation pour les professionnels du BTP. Concois un plan complet de developpement d'une expertise en renovation energetique pour un maitre d'oeuvre. Analyse : (1) formations et certifications a acquerir - RGE, OPQIBI, formation thermique - avec couts, durees et organismes, (2) connaissance des aides et subventions - MaPrimeRenov', CEE, PTZ, aides locales - pour devenir un conseiller de reference, (3) nouvelles missions liees a la RE - audit, AMO, DPE, accompagnement financement, (4) canaux d'acquisition specifiques a ce segment - ANAH, coproprietes, agences immobilieres, (5) projection du CA additionnel et de la montee en tarif lies a cette specialisation." },
  { id: "s4-145", category: "maitre-oeuvre-btp", title: "Strategie juridique de protection et de gestion des litiges", content: "Tu es un expert en droit de la construction pour les maitres d'oeuvre independants. Concois un cadre juridique complet de protection et de gestion des litiges. Inclus : (1) contrats types a utiliser selon la mission - CCMI, contrat de maitrise d'oeuvre, CCAP - avec clauses essentielles de protection, (2) assurances obligatoires et recommandees - RC professionnelle, decennale, tous risques chantier - avec niveaux de couverture optimaux, (3) processus de gestion des reserves et de la reception - proces-verbal type, delais legaux, obligations de levee, (4) strategie amiable de resolution des litiges - MARC, mediation, expertise - avant recours judiciaire, (5) constitution du dossier probatoire en cours de chantier pour se proteger en cas de litige ulterieur." },
  { id: "s4-146", category: "maitre-oeuvre-btp", title: "Optimisation de la rentabilite des missions", content: "Tu es un expert en gestion financiere pour les maitres d'oeuvre independants. Concois un systeme complet d'analyse et d'optimisation de la rentabilite des missions. Construis : (1) modele de calcul du cout de revient reel d'une mission - temps passe par phase, deplacements, sous-traitances, overhead, (2) structure tarifaire optimale selon le type de mission et le marche local - forfait, pourcentage travaux, assistance, (3) identification des phases de mission chronophages et peu valorisees et strategie pour les optimiser ou les deleguer, (4) politique d'avenants pour les prestations hors contrat - cadre contractuel, seuil de declenchement, tarification, (5) tableau de bord de rentabilite par mission avec seuil d'alerte et decision d'action corrective." },
  { id: "s4-147", category: "maitre-oeuvre-btp", title: "Developpement d'une activite de conseil en construction", content: "Tu es un expert en developpement de services a valeur ajoutee pour les maitres d'oeuvre. Concois une offre de conseil en construction pour un maitre d'oeuvre souhaitant valoriser son expertise au-dela de la conduite de chantier. Analyse : (1) services de conseil a developper - assistance a maitrise d'ouvrage, audit technique de bien avant achat, conseil en rehabilitation, expertise amiable, (2) tarification des missions de conseil - differenciation avec les missions d'execution, valeur percue, marche, (3) clients cibles par service - investisseurs, particuliers acheteurs, marchands de biens, syndics, (4) canaux d'acquisition specifiques au conseil - notaires, agents immobiliers, experts-comptables, (5) construction du positionnement expert et des supports de credibilite - portfolio, certifications, publications." },
  { id: "s4-148", category: "maitre-oeuvre-btp", title: "Strategie de recrutement et de developpement d'une equipe", content: "Tu es un expert en developpement RH pour les maitres d'oeuvre en croissance. Concois un plan complet de constitution et de developpement d'une equipe autour d'un maitre d'oeuvre independant souhaitant croitre. Analyse : (1) seuil de CA et de charge de travail justifiant le premier recrutement - conducteur de travaux, assistant technique, secretaire technique, (2) profils et missions des premiers recrutements selon la strategie de developpement, (3) organisation optimale du travail en equipe - repartition des missions, autonomie, controle qualite, (4) impact financier - couts, CA supplementaire possible, delai de retour sur investissement, (5) transition de l'expertise artisanale vers le management d'equipe - competences a developper, pieges a eviter." },
  { id: "s4-149", category: "maitre-oeuvre-btp", title: "Plan de communication et de portfolio", content: "Tu es un expert en communication pour les professionnels du BTP. Concois une strategie complete de communication et de developpement du portfolio pour un maitre d'oeuvre independant. Construis : (1) structure et contenu d'un portfolio professionnel convaincant - projets a selectionner, presentation par type de travaux, donnees chiffrees, visuels avant/apres, (2) strategie LinkedIn pour developper la notoriete professionnelle - contenu, frequence, cibles, (3) site web vitrine optimal - architecture, pages essentielles, SEO local, formulaire de contact, (4) strategie de collecte de temoignages et etudes de cas detaillees - processus, format, utilisation, (5) supports de presentation pour les rendez-vous prospects - presentation de l'agence, references, methodologie." },
  { id: "s4-150", category: "maitre-oeuvre-btp", title: "Gestion de la tresorerie et des flux financiers", content: "Tu es un expert en gestion financiere pour les maitres d'oeuvre independants. Concois un systeme complet de gestion de la tresorerie et des flux financiers pour une activite de maitrise d'oeuvre. Inclus : (1) structure de facturation optimale - acompte, appels de fonds lies a l'avancement, solde - pour maintenir une tresorerie positive, (2) politique de paiement des entreprises coordonnee avec les encaissements clients, (3) gestion des impayes - relances progressives, mise en demeure, recours, interets de retard, (4) prevision de tresorerie sur 12 mois glissants - outil simple, indicateurs d'alerte, actions preventives, (5) constitution d'une reserve de precaution et gestion des aleas de tresorerie lies aux decalages de paiement." },
];
